INSERT INTO `publications` (`id`, `user_id`, `title`, `annotation`, `content`, `file_path`, `file_original_name`, `file_size`, `file_type`, `publication_type_id`, `slug`, `meta_title`, `meta_description`, `views_count`, `downloads_count`, `status`, `moderation_comment`, `moderation_type`, `moderated_at`, `gpt_confidence`, `certificate_status`, `published_at`, `created_at`, `updated_at`) VALUES (6,668,'Семья – самое главное в жизни для каждого из нас','Возрастание роли образования, которое наблюдается в нашей стране, меняет отношение к дошкольным учреждениям. Современные условия деятельности дошкольных учреждений выдвигают взаимодействие с семьей на одно из ведущих мест,  родители являются основными социальными заказчиками МДОУ, поэтому взаимодействие педагогов с ними просто невозможно без учета запросов семьи.',NULL,'2026/02/pub_20260214_054344_fdf7394c.pdf','Семья_самое_главное _в_жизни_Потылицына_НН.pdf',172522,'application/pdf',2,'semya-samoe-glavnoe-v-zhizni-dlya-kazhdogo-iz-nas',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'paid','2026-02-14 05:43:44','2026-02-14 02:43:44','2026-02-14 02:44:36'),(7,723,'«Шерлок Холмс и тайна украденного Гербария»','План-конспект: «Шерлок Холмс и тайна украденного Гербария»\r\nПриурочено ко Всероссийскому дню науки (8 февраля)\r\nУчитель: «Ребята,8 февраля в нашей стране великий день- День российской науки! \r\nЗнаете ли вы, что всё вокруг нас – это химия? Воздух, вода, еда и даже мы сами. \r\nХимики – это учёные, которые изучают, как одни вещества превращаются в другие. \r\nСегодня вы станете творцами этих превращений.',NULL,'2026/02/pub_20260217_044333_d155d099.pdf','хим-био к дню науки 2026.pdf',338469,'application/pdf',1,'sherlok-holms-i-tayna-ukradennogo-gerbariya',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'pending','2026-02-17 04:43:33','2026-02-17 01:43:33','2026-02-17 01:43:33'),(8,723,'\"Шерлок Холмс и тайна украденного Гербария\"','Ребята, 8 февраля в нашей стране великий день - День российской науки! Знаете ли вы, что все вокруг нас - это химия!',NULL,'2026/02/pub_20260217_045511_70c43a2d.pdf','хим-био к дню науки 2026.pdf',338469,'application/pdf',1,'sherlok-holms-i-tayna-ukradennogo-gerbariya-1',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'ready','2026-02-17 04:55:11','2026-02-17 01:55:11','2026-02-26 01:41:54'),(9,760,'Роль педагога-психолога в сопровождении адаптационного периода в группах раннего возраста ДОУ','Одним из важных направлений работы педагога-психолога в ДОУ является: «Сопровождение адаптации детей раннего возраста». \r\n   Работа психолога ведётся со всеми участниками образовательного процесса. Это администрация ДОУ, воспитатели, дети и их родители.   \r\n           В последнее время проблема психолого-педагогического сопровождения детей раннего возраста в период адаптации к ДОУ стала чрезвычайно актуальной.',NULL,'2026/02/pub_20260218_092523_5dd209ee.pdf','семинар.pdf',783333,'application/pdf',8,'rol-pedagoga-psihologa-v-soprovozhdenii-adaptatsionnogo-perioda-v-gruppah-rannego-vozrasta-dou',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'pending','2026-02-18 09:25:23','2026-02-18 06:25:23','2026-02-18 06:25:23'),(10,510,'Речь родителей - образец для ребенка','Любой родитель хочет видеть своего ребенка успешным и уверенным в себе. Немаловажную роль для достижения этой цели играет красивая, правильная речь. Не имеет значения, кем в будущем станет ваш ребенок. Четкая, грамотная речь пригодится в любой сфере деятельности. Очень большое значение для развития речи ребенка имеет речевая среда, в которой он растет.',NULL,'2026/02/pub_20260219_073038_ab3f2b1c.pdf','Речь родителей образец для ребенка.pdf',854260,'application/pdf',2,'rech-roditeley-obrazets-dlya-rebenka',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'paid','2026-02-19 07:30:38','2026-02-19 04:30:38','2026-02-19 04:37:34'),(11,510,'Консультация для родителей \"Звуковой анализ слова\"','Под звуковым анализом слова понимается определение порядка следования звуков в слове, установление различительной роли звука, основных качественных характеристик звука.',NULL,'2026/02/pub_20260219_073315_13730578.pdf','Звуковой анализ слова.pdf',320906,'application/pdf',5,'konsultatsiya-dlya-roditeley-zvukovoy-analiz-slova',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'paid','2026-02-19 07:33:15','2026-02-19 04:33:15','2026-02-19 04:37:34'),(12,821,'Наследие земли Ямала: Искусство орнаментов народов Севера','Данная  тема является актуальной, так как через изучение традиционной культуры мы открываем в себе новые грани знания, учимся уважать и понимать традиции других народов, уважать их устои. Интерес к различным орнаментам северных народов возник в связи с тем, что в повседневной жизни дети часто встречают традиционные орнаменты, не задумываясь о их происхождении и предназначении.',NULL,'2026/02/pub_20260220_072727_c6700c3b.pdf','stendovy_doklad_Tayshina_V.pdf',762486,'application/pdf',3,'nasledie-zemli-yamala-iskusstvo-ornamentov-narodov-severa',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'ready','2026-02-20 07:27:27','2026-02-20 04:27:27','2026-02-27 05:29:29'),(13,849,'\"Экологическое воспитание  детей: от формирования сознания  к экологическим  привычкам\"','Экологическое воспитание  детей: от формирования сознания  к экологическим  привычкам.Как внимание педагога  фокусируется на обучении  детей практическим  навыкам защиты природы.',NULL,'2026/02/pub_20260221_125129_8a6d8fb0.pdf','АКТИВНЫЕ МЕТОДЫ В ФОРМИРОВАНИИ ОСОЗНАННОГО ЭКОЛОГИЧЕСКОГО МИРОВОЗЗРЕНИЯ В ОБРАЗОВАНИИ.pdf',302661,'application/pdf',8,'ekologicheskoe-vospitanie-detey-ot-formirovaniya-soznaniya-k-ekologicheskim-privychkam',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'ready','2026-02-21 12:51:29','2026-02-21 09:51:29','2026-02-27 19:04:26'),(14,1059,'План конспект занятия по английскому языку в 7 классе  по теме \"Пословицы и скороговорки\"','Данное занятие можно использовать для знакомства ребят 7 класса с английским фольклором.',NULL,'2026/02/pub_20260224_094101_04015935.doc','План-конспект Пословицы и скороговорки на англ яз.doc',56320,'application/msword',1,'plan-konspekt-zanyatiya-po-angliyskomu-yazyku-v-7-klasse-po-teme-poslovitsy-i-skorogovorki',NULL,NULL,0,0,'pending',NULL,NULL,NULL,NULL,'ready','2026-02-24 09:41:01','2026-02-24 06:41:01','2026-02-25 09:33:28'),(15,5,'Роль воспитателя в развитии социально-эмоциональной сферы дошкольников','Публикация рассматривает важность социально-эмоционального развития детей дошкольного возраста и роль воспитателя в этом процессе. Описываются методы и примеры работы воспитателя для формирования у детей эмпатии, навыков сотрудничества и управления эмоциями.','<p>Роль воспитателя в развитии социально-эмоциональной сферы детей дошкольного возраста</p>\n<p>Введение</p>\n<p>В дошкольном возрасте дети активно познают окружающий мир и самих себя. Одним из ключевых аспектов их развития является социально-эмоциональная сфера, которая определяет способность детей взаимодействовать с окружающими, выражать свои чувства и управлять эмоциями. Воспитатель играет важнейшую роль в этом процессе, создавая благоприятную атмосферу для формирования у детей необходимых навыков.</p>\n<p>Основная часть</p>\n<p>1. Значение социально-эмоционального развития</p>\n<p>Социально-эмоциональное развитие детей включает в себя формирование таких качеств, как эмпатия, умение сотрудничать, управлять своими эмоциями и устанавливать контакты с другими. Эти навыки необходимы для успешной адаптации в обществе и дальнейшего личностного роста.</p>\n<p>2. Роль воспитателя</p>\n<p>Воспитатель в детском саду является не только наставником, но и примером для подражания. Его задача – создать условия, в которых дети смогут безопасно выражать свои эмоции, учиться понимать чувства других и развивать навыки общения.</p>\n<p>Создание благоприятной атмосферы: Воспитатель должен уметь создавать атмосферу доверия и поддержки, где каждый ребенок чувствует себя принятым и понятым.</p>\n<p>Эмоциональная поддержка: Важно быть чутким к эмоциональным состояниям детей, помогать им справляться с негативными эмоциями и радоваться успехам.</p>\n<p>Обучение через игру: Игра – основной вид деятельности дошкольников. Воспитатель использует игровые методы для обучения детей социальным и эмоциональным навыкам.</p>\n<p>3. Примеры работы воспитателя</p>\n<p>Ролевые игры: Организация сюжетно-ролевых игр, где дети могут проигрывать различные социальные ситуации, учиться взаимодействовать и решать конфликты.</p>\n<p>Обсуждение эмоций: Проведение бесед о чувствах, где дети учатся распознавать и называть свои эмоции и эмоции других.</p>\n<p>Совместные проекты: Работа над общими проектами, которые требуют сотрудничества и взаимопомощи, развивает у детей чувство ответственности и умение работать в команде.</p>\n<p>Заключение</p>\n<p>Социально-эмоциональное развитие детей – это непрерывный процесс, требующий внимания и участия воспитателя. Только совместными усилиями можно создать условия, в которых каждый ребенок будет расти уверенным, доброжелательным и готовым к успешному взаимодействию с окружающим миром.</p>','2026/02/pub_20260225_110147_2a81e850.docx','7eea2fc0f2d7c3b146a7e37e5f47294c.docx',13770,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',2,'rol-vospitatelya-v-razvitii-sotsialno-emotsionalnoy-sfery-doshkolnikov',NULL,NULL,59,0,'published',NULL,'auto_approved','2026-02-25 11:01:48',0.95,'ready','2026-02-25 11:01:48','2026-02-25 08:01:47','2026-03-05 00:03:00'),(16,1595,'Рабочая программа дисциплины \'Физическая культура\'','Публикация представляет собой общую характеристику рабочей программы дисциплины \'Физическая культура\' для среднего профессионального образования. Описываются цели, планируемые результаты и структура программы. Особое внимание уделяется формированию общих компетенций и развитию физических навыков у обучающихся.','<p>.</p>\n<p><strong>СОДЕРЖАНИЕ</strong></p>\n<p>1.    Общая характеристика рабочей программы общеобразовательной дисциплины «Физическая культура»3</p>\n<p>2. Структура и содержание общеобразовательной дисциплины9</p>\n<p>3. Условия реализации программы общеобразовательной дисциплины26</p>\n<p>4.    Контроль и оценка результатов освоения общеобразовательной дисциплины28</p>\n<ul>\n<li>Общая характеристика рабочей программы общеобразовательной дисциплины «Физическая культура»</li>\n</ul>\n<p><strong>1.1. Место дисциплины в структуре образовательной программы СПО: </strong></p>\n<p>Общеобразовательная дисциплина «<u>Физическая культура</u>» является обязательной частью общеобразовательного цикла образовательной программы в соответствии с ФГОС СПО по специальности 09.02.01  Компьютерные системы и комплексы. </p>\n<p><strong>1.2. Цели и планируемые результаты освоения дисциплины:</strong></p>\n<p><strong>1.2.1. Цели дисциплины</strong></p>\n<p>Содержание программы общеобразовательной дисциплины «Физическая культура» направлено на достижение следующих целей:  формирование разносторонней, физически развитой личности, способной активно использовать ценности физической культуры для укрепления и длительного сохранения собственного здоровья, развитие у обучающихся двигательных навыков, совершенствование всех видов физкультурной и спортивной деятельности,  гармоничное физическое развитие, формирование культуры здорового и безопасного образа жизни будущего квалифицированного специалиста.</p>\n<p><strong>1.2.2. Планируемые результаты освоения общеобразовательной дисциплины в соответствии с ФГОС СПО и на основе ФГОС СОО</strong></p>\n<p>Особое значение дисциплина имеет при формировании и развитии ОК01, ОК04, ОК08.</p>\n<table>\n<tr>\n<th>Код и наименование формируемых компетенций</th>\n<th colspan=\"2\">Планируемые результаты</th>\n</tr>\n<tr>\n<td>Общие</td>\n<td>Дисциплинарные</td>\n</tr>\n<tr>\n<td>ОК 01. Выбирать способы решения задач профессиональной деятельности применительно к различным контекстам </td>\n<td>В части трудового воспитания:<br>- готовность к труду, осознание ценности мастерства, трудолюбие; <br>- готовность к активной деятельности технологической и социальной направленности, способность инициировать, планировать и самостоятельно выполнять такую деятельность; <br>- интерес к различным сферам профессиональной деятельности,<br>Овладение универсальными учебными познавательными действиями:<br> а) базовые логические действия:<br>- самостоятельно формулировать и актуализировать проблему, рассматривать ее всесторонне; <br>- устанавливать существенный признак или основания для сравнения, классификации и обобщения; <br>- определять цели деятельности, задавать параметры и критерии их достижения;<br>- выявлять закономерности и противоречия в рассматриваемых явлениях; <br>- вносить коррективы в деятельность, оценивать соответствие результатов целям, оценивать риски последствий деятельности; <br>- развивать креативное мышление при решении жизненных проблем <br>б) базовые исследовательские действия:<br>- владеть навыками учебно-исследовательской и проектной деятельности, навыками разрешения проблем; <br>- выявлять причинно-следственные связи и актуализировать задачу, выдвигать гипотезу ее решения, находить аргументы для доказательства своих утверждений, задавать параметры и критерии решения; <br>- анализировать полученные в ходе решения задачи результаты, критически оценивать их достоверность, прогнозировать изменение в новых условиях; <br>- уметь переносить знания в познавательную и практическую области жизнедеятельности;<br>- уметь интегрировать знания из разных предметных областей; <br>- выдвигать новые идеи, предлагать оригинальные подходы и решения; <br>- способность их использования в познавательной и социальной практике </td>\n<td>ПРб 2. Владение современными технологиями укрепления и сохранения здоровья, поддержания работоспособности, профилактики заболеваний, связанных с учебной и производственной деятельностью; <br>ПРб 4. владение физическими упражнениями разной функциональной направленности, использование их в режиме учебной и производственной деятельности с целью профилактики переутомления и сохранения высокой работоспособности; <br>ПРб 5. Владение техническими приемами и двигательными действиями базовых видов спорта, активное применение их в физкультурно-оздоровительной и соревновательной деятельности, в сфере досуга, в профессионально-прикладной сфере;</td>\n</tr>\n<tr>\n<td>ОК 04. Эффективно взаимодействовать и работать в коллективе и команде</td>\n<td>- готовность к саморазвитию, самостоятельности и самоопределению;<br>-овладение навыками учебно-исследовательской, проектной и социальной деятельности;<br>Овладение универсальными коммуникативными действиями:<br>б) совместная деятельность:<br>- понимать и использовать преимущества командной и индивидуальной работы;<br>- принимать цели совместной деятельности, организовывать и координировать действия по ее достижению: составлять план действий, распределять роли с учетом мнений участников обсуждать результаты совместной работы;<br>- координировать и выполнять работу в условиях реального, виртуального и комбинированного взаимодействия;<br>- осуществлять позитивное стратегическое поведение в различных ситуациях, проявлять творчество и воображение, быть инициативным<br>Овладение универсальными регулятивными действиями:<br>г) принятие себя и других людей:<br>- принимать мотивы и аргументы других людей при анализе результатов деятельности;<br>- признавать свое право и право других людей на ошибки;<br>- развивать способность понимать мир с позиции другого человека</td>\n<td>ПРб 4. владение физическими упражнениями разной функциональной направленности, использование их в режиме учебной и производственной деятельности с целью профилактики переутомления и сохранения высокой работоспособности; <br>ПРб 5. Владение техническими приемами и двигательными действиями базовых видов спорта, активное применение их в физкультурно-оздоровительной и соревновательной деятельности, в сфере досуга, в профессионально-прикладной сфере</td>\n</tr>\n<tr>\n<td>ОК 08 Использовать средства физической культуры для сохранения и укрепления здоровья в процессе профессиональной деятельности и поддержания необходимого уровня физической подготовленности</td>\n<td>готовность к саморазвитию, самостоятельности и самоопределению;<br>наличие мотивации к обучению и личностному развитию;<br>В части физического воспитания:<br>- сформированность здорового и безопасного образа жизни, ответственного отношения к своему здоровью;<br>- потребность в физическом совершенствовании, занятиях спортивно-оздоровительной деятельностью;<br>- активное неприятие вредных привычек и иных форм причинения вреда физическому и психическому здоровью;<br>Овладения универсальными регулятивными действиями:<br>- самостоятельно составлять план решения проблемы с учётом имеющихся ресурсов, собственных возможностей и предпочтений;<br>- давать оценку новым ситуациям;<br>- расширять рамки учебного предмета на основе личных предпочтений;<br>- делать осознанный выбор, аргументировать его, брать ответственность за решение;<br>- оценивать приобретённый опыт;<br>- способствовать формированию и проявлению широкой эрудиции в разных областях знаний; <br>- постоянно повышать свой образовательный и культурный уровень;</td>\n<td>ПРб 1. Умение использовать разнообразные формы и виды физкультурной деятельности для организации здорового образа жизни, активного отдыха и досуга, в том числе в подготовке к выполнению нормативов Всероссийского физкультурно-спортивного комплекса &quot;Готов к труду и обороне&quot; (ГТО); <br>ПРб 2. Владение современными технологиями укрепления и сохранения здоровья, поддержания работоспособности, профилактики заболеваний, связанных с учебной и производственной деятельностью; <br>ПРб 3. Владение основными способами самоконтроля индивидуальных показателей здоровья, умственной и физической работоспособности, динамики физического развития и физических качеств; <br>ПРб 4. владение физическими упражнениями разной функциональной направленности, использование их в режиме учебной и производственной деятельности с целью профилактики переутомления и сохранения высокой работоспособности; <br>ПРб 5. Владение техническими приемами и двигательными действиями базовых видов спорта, активное применение их в физкультурно-оздоровительной и соревновательной деятельности, в сфере досуга, в профессионально-прикладной сфере;<br>ПРб 6. Положительную динамику в развитии основных физических качеств (силы, быстроты, выносливости, гибкости и ловкости)</td>\n</tr>\n</table>\n<p>2. Структура и содержание общеобразовательной дисциплины</p>\n<p><strong>2.1. Объем дисциплины и виды учебной работы</strong></p>\n<table>\n<tr>\n<th>Вид учебной работы</th>\n<th>Объем в часах</th>\n</tr>\n<tr>\n<td>Объем образовательной программы дисциплины</td>\n<td>72</td>\n</tr>\n<tr>\n<td>самостоятельная работа</td>\n<td>4</td>\n</tr>\n<tr>\n<td>в т. ч.</td>\n<td></td>\n</tr>\n<tr>\n<td>Основное содержание</td>\n<td>66</td>\n</tr>\n<tr>\n<td colspan=\"2\">в т. ч.:</td>\n</tr>\n<tr>\n<td>теоретическое обучение</td>\n<td>4</td>\n</tr>\n<tr>\n<td>практические занятия </td>\n<td>62</td>\n</tr>\n<tr>\n<td>Профессионально-ориентированное содержание (содержание прикладного модуля)</td>\n<td>4</td>\n</tr>\n<tr>\n<td>в т. ч.:</td>\n<td></td>\n</tr>\n<tr>\n<td>теоретическое обучение</td>\n<td></td>\n</tr>\n<tr>\n<td>практические занятия </td>\n<td>4</td>\n</tr>\n<tr>\n<td>Промежуточная аттестация (экзамен)</td>\n<td>2</td>\n</tr>\n</table>\n<p><strong>2.2. Тематический план и содержание дисциплины </strong></p>\n<table>\n<tr>\n<th>Наименование разделов и тем</th>\n<th>Содержание учебного материала (основное и профессионально-ориентированное), лабораторные и практические занятия, прикладной модуль (при наличии)</th>\n<th>Объем часов</th>\n<th>Формируемые компетенции</th>\n</tr>\n<tr>\n<td>1</td>\n<td>2</td>\n<td>3</td>\n<td>4</td>\n</tr>\n<tr>\n<td colspan=\"2\">1 семестр </td>\n<td>24</td>\n<td></td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 1. Теоретические занятия.</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Тема 1.1. <br>Современное состояние физической культуры и спорта. Здоровье и здоровый образ жизни</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Физическая культура как часть культуры общества и человека. Роль физической культуры в общекультурном, профессиональном и социальном развитии человека. Современное представление о физической культуре: основные понятия; основные направления развития физической культуры в обществе и их формы организации</td>\n</tr>\n<tr>\n<td>Всероссийский физкультурно-спортивный комплекс «Готов к труду и обороне» (ГТО) — программная и нормативная основа системы физического воспитания населения, история и развитие комплекса «Готов к труду и обороне». Характеристика нормативных требований для обучающихся СПО</td>\n</tr>\n<tr>\n<td>Здоровье как базовая ценность человека и общества. Характеристика основных компонентов здоровья, их связь с занятиями физической культуры. Факторы, определяющие здоровье. Психосоматические заболевания</td>\n</tr>\n<tr>\n<td>Понятие «здоровый образ жизни» и его составляющие: режим труда и отдыха, профилактика и устранение вредных привычек, оптимальный двигательный режим, личная гигиена, закаливание, рациональное питание</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 2. Практические занятия. Учебно-тренировочные занятия</td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 2.1. <br>Лёгкая атлетика </td>\n<td>Содержание учебного материала</td>\n<td>8</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n<td>8</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях легкой атлетикой. Техника бега высокого и низкого старта, стартового разгона, финиширования. 1000м<br>Совершенствование техники спринтерского бега.100м<br>Совершенствование техники (кроссового бега, средние и длинные дистанции (2 000 м (девушки) и 3 000 м (юноши))<br>Совершенствование техники эстафетного бега (4 *100 м, 4*400 м; бега по прямой с различной скоростью)<br>Совершенствование техники прыжка в длину с разбега<br>Совершенствование техники прыжка в длину с места <br>Совершенствование техники метания гранаты весом 500 г (девушки) и 700 г (юноши); <br>Развитие физических способностей средствами лёгкой атлетики Подвижные игры и эстафеты с элементами легкой атлетики.</td>\n<td></td>\n</tr>\n<tr>\n<td>1. Техника безопасности на занятиях по легкой атлетике.  Техникой бега по прямой. Ознакомление с техникой метания гранаты. Зачет: Бег 100 м<br>Техника безопасности. Виды травм и их профилактика. Бег. СБУ. ОРУ. Техника бега по прямой. Техника низкого старта, выбегание со старта. Техника стартового разгона. Техника метания гранаты. Бег 100м.Бег по дорожкам, финиширование. Прыжки в длину с разбега: подбор шага, отталкивание, полет, приземление</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Техника эстафетного бега: передача эстафетной палочки. Бег 100 м. Зачет: Бег 1000 м<br>Техника безопасности. Бег. ОРУ. СБУ. Техника передачи эстафетной палочки, способы передачи. Техника передачи эстафетной палочки в «коридоре». Бег 100м. Передача эстафетной палочки. Техника эстафетного бега в команде (4×100м.). Бег по виражу. Как работает секундомер на старте и на финише. Работа судей на дистанции и на финише <br>Техника прыжков в длину с места. Техника подготовительной фазы прыжка с места. Техника фазы отталкивания прыжка с места. Техника фазы приземления прыжка с места. Выполнение прыжков в длину с места, прорабатывание каждого элемента.  Техника бега на 400 м.</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Техника бега с низкого старта. Совершенствование прыжков в длину с разбега. Зачет: Бег 800 м<br>Техника безопасности. Бег. Скоростно-прыжковые упражнения.  Техника выбегания с низкого старта. Техника финиширования. Техника прыжка в длину с разбега. Техника приземления на обе ноги. Техника бега на 800 метров</td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Техника прыжков в длину с разбега. Бег 800 м. Зачет: 2 км (д), 3 км (ю)<br>Техника безопасности. Бег. ОРУ на ягодицы. Техника бега на 800м. Вхождение в вираж. Техника прыжков в длину с разбега, перечислить ошибки. Техника прыжка в длину с места.<br>Бег 1000 м.  в медленном темпе</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.2.Волейбол </td>\n<td>Содержание учебного материала</td>\n<td>12</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n<td>12</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях волейболом. Освоение и совершенствование техники выполнения приёмов игры: стойки игрока, перемещения, передача мяча, подача, нападающий удар, прием мяча снизу двумя руками, прием мяча одной рукой с последующим нападением и перекатом в сторону, на бедро и спину, прием мяча одной рукой в падении.<br>Освоение/совершенствование приёмов тактики защиты и нападения.<br>Выполнение технико-тактических приёмов в игровой деятельности</td>\n<td></td>\n</tr>\n<tr>\n<td>1.Знакомство с правилами игры. Совершенствование стоек и перемещений волейболиста. Учебная игра. Зачет: Передача мяча у стены двумя руками сверху, снизу<br>Виды травм и их профилактика. Ходьба, бег, бег с заданием. ОРУ. Техника безопасности с волейбольным мячом. Стойка волейболиста. Техника передач волейбольного мяча сверху (работа у стенки и в парах).  <br>Техника передач волейбольного мяча снизу (работа у стенки и в парах).  Зачет: Передача мяча у стены двумя руками сверху и снизу. Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Совершенствование техники верхнего приема стоя на месте и после перемещения. Учебная игра. Зачет: Передача мяча в парах, двумя руками сверху, снизу<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Стойка волейболиста. Владение техническими приемами. Зачет: Передача мяча в парах, двумя руками снизу.  Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Совершенствование   верхнего приема в движении. Учебная игра. Зачет: Прием мяча над собой двумя руками, передача двумя руками сверху партнеру<br>Техника безопасности при работе с мячами. Ходьба, бег, бег с заданием. ОРУ. Совершенствование верхнего приема в движении. Подача мяча верхняя, нижняя.  Прием мяча над собой в кругу двумя руками сверху. Учебная игра Зачет: Прием мяча над собой двумя руками, передача двумя руками сверху партнеру. </td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Дальнейшее совершенствование верхнего, нижнего приема волейбольного мяча. Общефизическая подготовка. Учебная игра. Заполнение протокола. Зачет: над собой в кругу двумя руками сверху, снизу<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Дальнейшее совершенствование верхнего, нижнего приема волейбольного мяча.  Зачет: над собой в кругу двумя руками сверху. Выполнить подачу мяча посредством учебной игры.  Зачет: над собой в кругу двумя руками снизу. Заполнение протокола игры</td>\n<td>2</td>\n</tr>\n<tr>\n<td>5.Совершенствование передач сверху, снизу после перемещения, с изменением направления. Приемы мяча с подачи, вторая передача мяча в зоне 2 и 4. Учебная игра. Зачет: Верхняя подача. Нижняя подача<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Дальнейшее знакомство с правилами. Совершенствование передач сверху, снизу после перемещения, с изменением направления. Прием мяча с подачи, вторая передача мяча в зоне 2 и 4. Совершенствование техники передачи мяча сверху, снизу, в более сложных условиях. Обучение перебиванию мяча через сетку кулаком в прыжке. Прием мяча двумя руками сверху, попадание в баскетбольный щит из 10 попыток. Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>6.Совершенствование перебивания мяча через сетку кулаком в прыжке. ОРУ. Учебная игра. Зачет: Упражнения в тройках: прием и передача двумя руками сверху с передвижением<br>Техника безопасности с волейбольным мячом. Ходьба, бег, бег с заданием. ОРУ. Совершенствование приемов мяча сверху, снизу (стоя на месте и после перемещений, с подачи). Совершенствование перебивания мяча через сетку кулаком в прыжке. Упражнения в четверках через сетку. Учебная игра Закрепление всех изученных приемов посредством учебной игры. Заполнение протокола. Судейство.</td>\n<td>2</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 3. Практические занятия. Профессионально ориентированное содержание</td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 3.1. Составление и проведение комплексов упражнений для различных форм организации занятий физической культурой при решении профессионально-ориентированных задач</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Освоение методики составления и проведения комплексов упражнений для производственной гимнастики, комплексов упражнений для профилактики профессиональных заболеваний с учётом специфики будущей профессиональной деятельности. Освоение методики составления и проведения комплексов упражнений для профессионально-прикладной физической подготовки с учётом специфики будущей профессиональной деятельности. Характеристика профессиональной деятельности: группа труда, рабочее положение, рабочие движения, функциональные системы, обеспечивающие трудовой процесс, внешние условия или производственные факторы, профессиональные заболевания. Освоение комплексов упражнений для производственной гимнастики различных групп профессий (первая, вторая, третья, четвертая группы профессий)</td>\n</tr>\n<tr>\n<td colspan=\"2\">2 семестр </td>\n<td>48</td>\n<td></td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 1. Теоретические занятия.</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Тема 1.1. <br>Современное состояние физической культуры и спорта. Здоровье и здоровый образ жизни</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Общие представления об истории и развитии популярных систем оздоровительной физической культуры, их целевая ориентация и предметное содержание. Представления о современных системах и технологиях укрепления и сохранения здоровья (дыхательная гимнастика, антистрессовая гимнастика, глазодвигательная гимнастика, суставная гимнастика, оздоровительная ходьба, северная или скандинавская ходьба и оздоровительный бег и др.)<br>Особенности организации и проведения занятий в разных системах оздоровительной физической культуры и их функциональная направленность Формы организации самостоятельных занятий оздоровительной физической культурой и их особенности; соблюдение требований безопасности и гигиенических норм и правил во время занятий физической культурой</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 2. Профессионально ориентированное содержание</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Тема 2.1. <br>Подбор упражнений, составление и проведение комплексов упражнений для различных форм организации занятий физической культурой</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Освоение методики составления и проведения комплексов упражнений утренней зарядки, физкультминуток, физкультпауз, комплексов упражнений для коррекции осанки и телосложения<br>Освоение методики составления и проведения комплексов упражнений различной функциональной направленности</td>\n</tr>\n<tr>\n<td>В том числе самостоятельная работа <br>Составить комплекс ОРУ</td>\n<td>2</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 2. Практические занятия. Учебно-тренировочные занятия</td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 2.2.<br>Баскетбол</td>\n<td>Содержание учебного материала</td>\n<td>18</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n<td>18</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях баскетболом. Освоение и совершенствование техники выполнения приёмов игры:<br>перемещения, остановки, стойки игрока, повороты; ловля и передача мяча двумя и одной рукой, на месте и в движении, с отскоком от пола;  ведение мяча на месте, в движении, по прямой с изменением скорости, высоты отскока и направления, по зрительному и слуховому сигналу; броски одной рукой, на месте, в движении, от груди, от плеча; бросок после ловли и после ведения мяча, бросок мяча. Освоение и совершенствование приёмов тактики защиты и нападения. Выполнение технико-тактических приёмов в игровой деятельности</td>\n<td></td>\n</tr>\n<tr>\n<td>1.Техника безопасности. Правила в баскетболе. Ведение, передача мяча. Вырывания, выбивания мяча. Зачет: Вырывание, выбивание. Штрафной бросок<br>Техника безопасности при работе с баскетбольным мячом. Ходьба, бег, бег с заданием. ОРУ. Правила в баскетболе. Передача мяча: двумя руками сверху, двумя руками снизу, двумя руками от груди, двумя руками из- за головы, правой, левой от плеча. Ведение правой, левой рукой, разноименной, передача мяча от груди, с отскоком от пола.   Зачет: Вырывание, выбивание мяча. Штрафные броски. Игра 10 передач<br> Передача мяча: двумя руками сверху, двумя руками снизу, двумя руками от груди, двумя руками из- за головы, правой, левой от плеча. Ведение правой, левой рукой, разноименной, передача мяча от груди, с отскоком от пола. </td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Ознакомление с обманными действиями. Броски мяча в кольцо. Тактика игры. Учебная игра.   Зачет: Ведение двух мячей на месте и в движении. Броски с 6 точек</td>\n<td>4</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Передача мяча: двумя руками сверху, двумя руками снизу, одной рукой снизу, одной рукой над головой, двумя руками от груди, двумя руками из- за головы, правой левой от плеча. Ведение двух мячей на месте и вдвижении.  Обманные действия. Тактика игры. Броски мяча в кольцо. Ведение, два шага, атака на щит. Броски с 6 точек за 1 минуту. Учебная игра. Игра «-5»</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Передача мяча. Обманные действия. Тактика игры. Броски мяча в кольцо. Ведение, два шага, атака на щит. Броски с 6 точек за 1 минуту.  Зачет: Ведение двух мячей на месте и в движении.  Броски с 6 точек. Учебная игра. Игра «-5»</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Обманные действия. Повторение техники игры в защите, в нападении. Учебная игра.    Зачет: Ведение два шага, атака на щит</td>\n<td>4</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Передача мяча: двумя руками сверху, двумя руками снизу, одной рукой снизу, одной рукой над головой, двумя руками от груди, двумя руками из- за головы, правой левой от плеча. Обманные действия.  Повторение техники игры в защите, в нападении. Передвижение в двойках, атака на щит. Ведение два шага, атака на щит. Учебная игра. Игра «33».</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Передача мяча. Обманные действия.  Повторение техники игры в защите, в нападении. Передвижение в двойках, атака на щит.  Зачет: Ведение два шага, атака на щит. Учебная игра. Игра «33».</td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Совершенствование ловли мяча: двумя руками от груди, с отскоком от пола. Учебная игра, судейство. Зачет: Передвижение в двойках, атака на щит</td>\n<td>4</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Ведение правой, левой рукой, передача мяча правой, левой, от груди, с отскоком от пола. Совершенствование ловли мяча: двумя руками от груди, с отскоком от пола. Передвижение в тройках, атака на щит. Передвижение в двойках, атака на щит.  Учебная игра. «Стритбол». Судейство </td>\n<td>2</td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Ведение правой, левой рукой, передача мяча правой, левой, от груди, с отскоком от пола. Совершенствование ловли мяча: двумя руками от груди, с отскоком от пола. Зачет: Передвижение в двойках, атака на щит.  Учебная игра. «Стритбол». Судейство </td>\n<td>2</td>\n</tr>\n<tr>\n<td>5.Тактика игры в защите. Личная защита. Двухсторонняя игра. Заполнение протокола судейства. Штрафной бросок. Судейство. Зачет: Передвижение в тройках, атака на щит</td>\n<td>4</td>\n</tr>\n<tr>\n<td></td>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Ведение, передача мяча.  Ведение правой, левой рукой, передача мяча правой, левой, от груди, с отскоком от пола.  Тактика игры в защите. Личная защита. Штрафной бросок (правила назначения штрафного броска за фолы и нарушения).  Передвижение в тройках, атака на щит. Заполнение протокола судейства. Двусторонняя игра</td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Ведение, передача мяча. Тактика игры в защите. Личная защита. Штрафной бросок. Зачет: Передвижение в тройках, атака на щит. Заполнение протокола судейства. Двусторонняя игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td></td>\n<td>В том числе самостоятельная работа<br>Заполнение протокола </td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 2.3. Основная гимнастика </td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04, <br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях гимнастикой. <br>Выполнение строевых упражнений, строевых приёмов: построений и перестроений, передвижений, размыканий и смыканий, поворотов на месте. <br>Выполнение общеразвивающих упражнений без предмета и с предметом; в парах, в группах, на снарядах и тренажерах.<br>Выполнение прикладных упражнений: ходьбы и бега, упражнений в равновесии, лазанье и перелазание, метание и ловля, поднимание и переноска груза, прыжки</td>\n</tr>\n<tr>\n<td>1.Техника безопасности на занятиях. Упражнения на укрепление мышц живота. Комплекс упражнений на гимнастической скамейке. Отягощения. Зачет: Упражнение «Циркуль»<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ на гибкость. Упражнения на гимнастических ковриках для развития мышц плечевого пояса, косых, боковых мышц спины. Закрепить комплекс на гимнастической скамейке по ширине спортивного зала. Выполнение комплекса, прорабатывание каждого элемента. Упражнения с грифом, «блинами». Отягощения</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.4. Акробатика</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04, <br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Освоение акробатических элементов: кувырок вперед, кувырок назад, длинный кувырок, кувырок через плечо, стойка на лопатках, мост, стойка на руках, стойка на голове и руках, переворот боком «колесо», равновесие «ласточка». Совершенствование акробатических элементов. Освоение и совершенствование акробатической комбинации (последовательность выполнения элементов в акробатической комбинации может изменяться):</td>\n</tr>\n<tr>\n<td>1.Упражнения в паре. Упражнения для мышц плечевого пояса, косых, боковых мышц спины. Техника кувырка вперед, работа над ошибками. Зачет: «Ласточка». Кувырок вперед. Стойка на лопатках<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ в парах. Упражнения для мышц плечевого пояса, косых, боковых мышц спины. Техника кувырка вперед, ласточка, стояка на лопатках, работа над ошибками</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.5 <br>Атлетическая гимнастика</td>\n<td>Содержание учебного материала</td>\n<td>4</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Выполнение упражнений и комплексов упражнений атлетической гимнастики для рук и плечевого пояса, мышц спины и живота, мышц ног с использованием собственного веса. Выполнение упражнений со свободными весами. Выполнение упражнений и комплексов упражнений с использованием новых видов фитнесс оборудования. Выполнение упражнений и комплексов упражнений на силовых тренажерах</td>\n</tr>\n<tr>\n<td>1.Общеразвивающие упражнения в парах. Упражнение на эспандере «колесико» Зачет: Пистолет на каждую ногу<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ в парах, упражнения с собственным весом. Упражнение на эспандере «колесико».  Виды травм и их профилактика. Игра в волейбол. Подготовка к выполнению нормативов Всероссийского физкультурно-спортивного комплекса «Готов к труду и обороне» (ГТО). Игра в волейбол</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Упражнения с гантелями, с собственным весом. Приседания с блинами.  Зачет: Приседания через скамейку в паре<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ с собственным весом. Упражнения с гантелями. Приседание с «блином»<br>Круговая тренировка:<br>-скакалка;<br>-гимнастическая скамейка;<br>-работа с обручами; <br>-планка малая; <br>-планка большая.</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.6.<br>Бадминтон</td>\n<td>Содержание</td>\n<td>10</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Техника выполнения приёмов игры: основные стойки, классическая универсальная хватка ракетки, техника ударов, перемещения игрока, подачи, удары по волану техника передвижения игрока к сетке, в стороны, назад. Тактика игры в бадминтон: тактика защиты, тактика нападения. Правила игры. Игра по упрощенным правилам на площадках разных размеров. Игра по правилам. Подвижные игры и эстафеты с элементами бадминтона. Техника безопасности на занятиях бадминтоном</td>\n<td>10</td>\n</tr>\n<tr>\n<td>В том числе практических занятий</td>\n</tr>\n<tr>\n<td>Освоение и совершенствование техники выполнения приёмов игры. Освоение и совершенствование приёмов тактики защиты и нападения. Выполнение технико-тактических приёмов в игровой деятельности. Развитие физических способностей средствами бадминтона</td>\n</tr>\n<tr>\n<td>1.Разучивание способов хвата ракетки, основной стойки бадминтониста. Разучивание ударов по волану.  Зачет: Набивание волана (жонглирование) попеременно открытой и закрытой стороной ракетки<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Разучивание способов хвата ракетки, основной стойки бадминтониста. Разучивание ударов по волану. Разучивание подачи и удара в упрощенных условиях. Движения, имитации справа, слева. Учебная игра в парах</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Закрепить хват ракетки. Формировать умение владеть воланом (чувство волана). Отрабатывать стойку бадминтониста.  Зачет: Выполнение короткой подачи закрытой, открытой стороной ракетки.<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ с воланом и ракеткой. Закрепить хват ракетки. Формировать умение владеть воланом (чувство волана). Отрабатывать стойку бадминтониста. Выполнение короткой подачи закрытой, открытой стороной ракетки в паре и через сетку. Зачет: Выполнение короткой подачи закрытой, открытой стороной ракетки. Учебная игра в парах</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Разучивание подачи и удара в упрощенных условиях. Зачет: Работа в паре верхний нижний прием.</td>\n<td>2</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ с воланом и ракеткой.  Ознакомить с техникой подачи и ударов. Отрабатывать стойку бадминтониста. Зачет: Работа в паре верхний прием. Учебная игра в парах, в четверках </td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Ознакомление с атакующим ударом. Судейство, ведение протокола.  Зачет: Работа в паре верхний, нижний прием через сетку. <br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Ознакомление с атакующим ударом. Удары по волану. Зачет: Работа в паре верхний прием через сетку.  Судейство. Ведение протокола. Учебная игра в парах, в четверках</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.7 Теннис</td>\n<td>Содержание </td>\n<td>4</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Техника выполнения приёмов игры: упражнения с мячом - «школа мяча»; способы хватки ракетки (для удара справа, слева, универсальная хватка); упражнения с ракеткой; упражнения с ракеткой и мячом. Технические элементы: удары по мячу, перемещения по площадке, передвижения игрока (старт из исходного положения, движение к мячу, «вход» в удар, «выход» из удара и повторный старт, выход на позицию наивысшей готовности для следующего ответа); подача, приём подачи (свеча). Тактика игры в теннис: тактика защиты, тактика нападения. Правила игры. Игра по упрощенным правилам. Игра по правилам. Подвижные игры и эстафеты с элементами тенниса. Техника безопасности на занятиях теннисом.</td>\n<td></td>\n</tr>\n<tr>\n<td>В том числе практических занятий</td>\n<td></td>\n</tr>\n<tr>\n<td>Освоение и совершенствование техники выполнения приёмов игры. Освоение и совершенствование приёмов тактики защиты и нападения. Выполнение технико-тактических приёмов в игровой деятельности. Развитие физических способностей средствами тенниса</td>\n<td></td>\n</tr>\n<tr>\n<td>1.Техника безопасности. Обучение и закрепление приема мяча с подачи. Подача справа и слева накатом. Правила игры. Ведение протокола. Зачет: Подача мяча справа из 10 попыток<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Обучение и закрепление приема мяча с подачи. Подача справа и слева накатом. Подача мяча справа из 10 попыток. Зачет: Подача мяча справа из 10 попыток.  Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Закрепление и совершенствование приема мяча с подачи. Судейство. Учебная игра.  Зачет: Подача мяча слева из 10 попыток<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Закрепление и совершенствование приема мяча с подачи. Подача мяча слева из 10 попыток. Судейство. Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.8. Футбол</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях футболом. Освоение и совершенствование техники выполнения приёмов игры: удар по мячу носком, серединой подъема, внутренней, внешней частью подъема; остановки мяча внутренней стороной стопы; остановки мяча внутренней стороной стопы в прыжке, остановки мяча подошвой. Правила игры и методика судейства. Техника нападения. Действия игрока без мяча: освобождение от опеки противника.  Освоение/совершенствование приёмов тактики защиты и нападения.<br>Выполнение технико-тактических приёмов в игровой деятельности (учебная игра)</td>\n</tr>\n<tr>\n<td colspan=\"2\">Промежуточная аттестация по дисциплине (экзамен)</td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td colspan=\"2\">Всего:</td>\n<td>72</td>\n<td></td>\n</tr>\n</table>\n<p>3. Условия реализации программы общеобразовательной дисциплины</p>\n<p>3.1. Для реализации программы дисциплины предусмотрены спортивные сооружения:</p>\n<p>спортивный зал, оснащенный спортивным инвентарём и оборудованием, обеспечивающим достижение результатов освоения дисциплины;</p>\n<p>оборудованные открытые спортивные площадки, обеспечивающие достижение результатов освоения дисциплины;</p>\n<p>Перечень оборудования и инвентаря спортивных сооружений:</p>\n<p><strong>Спортивные игры</strong></p>\n<p>Щит баскетбольный игровой (комплект), кольца баскетбольные, табло игровое, мяч баскетбольный №7 массовый, мяч баскетбольный №7 для соревнований, мяч баскетбольный №5 массовый, мяч футбольный №4 массовый, мяч футбольный №5 массовый, мяч футбольный №5 для соревнований, насос для накачивания мячей с иглой, жилетки игровые.</p>\n<p><strong>Гимнастика</strong></p>\n<p>Скамейка гимнастическая, комплект матов гимнастических, гимнастическая скамейка.</p>\n<p><strong>Легкая атлетика</strong></p>\n<p>Секундомер, граната для метания, эстафетная полочка. </p>\n<p><strong>Оборудование для проведения соревнований</strong></p>\n<p>Скамейка, сантиметр мерный, комплект для соревнований (форма), персональный компьютер (ведение мониторингов и иных документов)</p>\n<p><strong>Прочее</strong></p>\n<p>Аптечка медицинская.</p>\n<p><strong>Открытые спортивные площадки:</strong></p>\n<p> ворота футбольные, сетки для футбольных ворот, мячи футбольные, стартовые флажки, флажки красные и белые, палочки эстафетные, нагрудные номера, секундомеры.</p>\n<p><strong>3.2. Информационное обеспечение реализации программы</strong></p>\n<p>Библиотечный фонд образовательной организации имеет печатные и электронные образовательные и информационные ресурсы.</p>\n<p><strong>3.2.1. Основные печатные издания</strong></p>\n<ul>\n<li>Физическая культура (базовый уровень)», Андрюхина Т.В., Третьякова Н.В. /Под ред. Виленского М.Я. – ООО «Русское слово», 2019 г.</li>\n<li>Физическая культура. 10-11 классы: учебник для общеобразоват. организаций: базовый уровень / А.П. Матвеев. — М.: Просвещение, 2019. — 319 с.</li>\n<li>Физическая культура. 10-11 классы: Учебник для общеобразоват. учреждений / Г.И. Погадаев. — М.: ДРОФА / Учебник, 2019. — 288 с.</li>\n<li>Физическая культура. 10-11 классы: Учебник для общеобразоват. учреждений / А.П. Матвеев, Е.С. Палехова. — М.: Вентана-Граф / Учебник, 2019. — 160 с.</li>\n</ul>\n<p><strong>3.2.2. Основные электронные издания </strong></p>\n<ul>\n<li>Баскетбол, волейбол: учебное пособие для вузов / Е. В. Конеева [и др.]; под редакцией Е. В. Конеевой. — 2-е изд., перераб. и доп. — Москва: Издательство Юрайт, 2024. — 176 с. — (Высшее образование). — ISBN 978-5-534-19017-5. — Текст: электронный // Образовательная платформа Юрайт [сайт]. — URL: https://urait.ru/bcode/555755 </li>\n<li>Легкая атлетика: учебное пособие для среднего профессионального образования / А. А. Зайцев, С. Я. Луценко. — 3-е изд., перераб. и доп. — Москва: Издательство Юрайт, 2024. — 70 с. — (Профессиональное образование). — ISBN 978-5-534-19950-5. — Текст: электронный // Образовательная платформа Юрайт [сайт]. — URL: https://urait.ru/bcode/557365 </li>\n</ul>\n<p><strong>3.2.3. Дополнительные источники </strong></p>\n<ul>\n<li>Теннис, настольный теннис, бадминтон: учебное пособие для вузов / Е. В. Конеева [и др.]; под общей редакцией Е. В. Конеевой. — 3-е изд., перераб. и доп. — Москва: Издательство Юрайт, 2024. — 95 с. — (Высшее образование). — ISBN 978-5-534-19051-9. — Текст: электронный // Образовательная платформа Юрайт [сайт]. — URL: https://urait.ru/bcode/555844</li>\n<li><strong>Физическая культура:10-11-е классы: учебник: издание в </strong><strong>pdf</strong><strong>-формате / А.П. Матвеев, </strong><strong>Е. С.</strong><strong> </strong><strong>Палехова</strong><strong>. -6-е изд.,</strong><strong> </strong><strong>стер</strong><strong>.-</strong><strong>Москва: </strong><strong>Просвещение</strong><strong>,</strong><strong> </strong><strong>2022.-158[2]</strong><strong> </strong><strong>c</strong><strong>.: </strong><strong>ил. </strong><strong>ISBN</strong><strong> 978-5-09-101692-5 </strong><strong>(</strong><strong>электр</strong><strong>. </strong><strong>Изд.).</strong><strong> - Текст электронный. </strong><strong>ISBN</strong><strong> 978-5-09-094658-2 (</strong><strong>печ</strong><strong>. </strong><strong>изд</strong><strong>). </strong><strong> </strong></li>\n<li>Контроль и оценка результатов освоения общеобразовательной дисциплины</li>\n</ul>\n<p><strong>Контроль</strong> <strong>и оценка</strong> результатов освоения общеобразовательной дисциплины раскрываются через дисциплинарные результаты, направленные на формирование общих и профессиональных компетенций по разделам и темам содержания учебного материала.</p>\n<table>\n<tr>\n<th>Общая/профессиональная компетенция</th>\n<th>Раздел/Тема</th>\n<th>Тип оценочных мероприятия</th>\n</tr>\n<tr>\n<td>ОК 01. Выбирать способы решения задач профессиональной деятельности применительно к различным контекстам</td>\n<td>Темы 1.1, 1.2 ,2.2,<br>3.1, 3.2, 3.3, 3.4, 3.5,<br>2.3, 2.4, 2.5, 2.6, 2.7, 2.8,2.9</td>\n<td>составление словаря терминов, либо кроссворда<br>защита презентации/доклада-презентации<br>выполнение самостоятельной работы<br>составление комплекса физических упражнений для самостоятельных занятий с учетом индивидуальных особенностей,<br>составление профессиограммы<br>заполнение дневника самоконтроля<br>защита реферата<br>составление кроссворда<br>фронтальный опрос<br>контрольное тестирование<br>составление комплекса упражнений<br>оценивание практической работы<br>тестирование<br>демонстрация комплекса ОРУ,<br>сдача контрольных нормативов<br>сдача контрольных нормативов (контрольное упражнение)<br>сдача нормативов ГТО<br>выполнение упражнений на дифференцированном зачете (экзамен)</td>\n</tr>\n<tr>\n<td>ОК 04. Эффективно взаимодействовать и работать в коллективе и команде</td>\n<td>Темы 1.1, 1.2 ,2.2,<br>3.1, 3.2, 3.3, 3.4, 3.5,<br>2.3, 2.4, 2.5, 2.6, 2.7, 2.8,2.9</td>\n</tr>\n<tr>\n<td>ОК 08. Использовать средства физической культуры для сохранения и укрепления здоровья в процессе профессиональной деятельности и поддержания необходимого уровня физической подготовленности</td>\n<td>Темы 1.1, 1.2 ,2.2,<br>3.1, 3.2, 3.3, 3.4, 3.5,<br>2.3, 2.4, 2.5, 2.6, 2.7, 2.8, 2.9</td>\n</tr>\n</table>','2026/02/pub_20260227_061051_f0a3344e.docx','РП ФИЗ-РА 09.02.01 К11 Закружная.docx',98688,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',4,'rabochaya-programma-distsipliny-fizicheskaya-kultura',NULL,NULL,30,0,'published',NULL,'auto_approved','2026-02-27 06:10:51',0.95,'pending','2026-02-27 06:10:51','2026-02-27 03:10:51','2026-03-04 09:23:14'),(17,1595,'Рабочая программа дисциплины \'Физическая культура\'','Публикация представляет собой общую характеристику рабочей программы дисциплины \'Физическая культура\' для среднего профессионального образования. Описываются цели и планируемые результаты освоения дисциплины, её место в структуре образовательной программы и условия реализации.','<p>.</p>\n<p><strong>СОДЕРЖАНИЕ</strong></p>\n<p>1.    Общая характеристика рабочей программы общеобразовательной дисциплины «Физическая культура»3</p>\n<p>2. Структура и содержание общеобразовательной дисциплины9</p>\n<p>3. Условия реализации программы общеобразовательной дисциплины26</p>\n<p>4.    Контроль и оценка результатов освоения общеобразовательной дисциплины28</p>\n<ul>\n<li>Общая характеристика рабочей программы общеобразовательной дисциплины «Физическая культура»</li>\n</ul>\n<p><strong>1.1. Место дисциплины в структуре образовательной программы СПО: </strong></p>\n<p>Общеобразовательная дисциплина «<u>Физическая культура</u>» является обязательной частью общеобразовательного цикла образовательной программы в соответствии с ФГОС СПО по специальности 09.02.01  Компьютерные системы и комплексы. </p>\n<p><strong>1.2. Цели и планируемые результаты освоения дисциплины:</strong></p>\n<p><strong>1.2.1. Цели дисциплины</strong></p>\n<p>Содержание программы общеобразовательной дисциплины «Физическая культура» направлено на достижение следующих целей:  формирование разносторонней, физически развитой личности, способной активно использовать ценности физической культуры для укрепления и длительного сохранения собственного здоровья, развитие у обучающихся двигательных навыков, совершенствование всех видов физкультурной и спортивной деятельности,  гармоничное физическое развитие, формирование культуры здорового и безопасного образа жизни будущего квалифицированного специалиста.</p>\n<p><strong>1.2.2. Планируемые результаты освоения общеобразовательной дисциплины в соответствии с ФГОС СПО и на основе ФГОС СОО</strong></p>\n<p>Особое значение дисциплина имеет при формировании и развитии ОК01, ОК04, ОК08.</p>\n<table>\n<tr>\n<th>Код и наименование формируемых компетенций</th>\n<th colspan=\"2\">Планируемые результаты</th>\n</tr>\n<tr>\n<td>Общие</td>\n<td>Дисциплинарные</td>\n</tr>\n<tr>\n<td>ОК 01. Выбирать способы решения задач профессиональной деятельности применительно к различным контекстам </td>\n<td>В части трудового воспитания:<br>- готовность к труду, осознание ценности мастерства, трудолюбие; <br>- готовность к активной деятельности технологической и социальной направленности, способность инициировать, планировать и самостоятельно выполнять такую деятельность; <br>- интерес к различным сферам профессиональной деятельности,<br>Овладение универсальными учебными познавательными действиями:<br> а) базовые логические действия:<br>- самостоятельно формулировать и актуализировать проблему, рассматривать ее всесторонне; <br>- устанавливать существенный признак или основания для сравнения, классификации и обобщения; <br>- определять цели деятельности, задавать параметры и критерии их достижения;<br>- выявлять закономерности и противоречия в рассматриваемых явлениях; <br>- вносить коррективы в деятельность, оценивать соответствие результатов целям, оценивать риски последствий деятельности; <br>- развивать креативное мышление при решении жизненных проблем <br>б) базовые исследовательские действия:<br>- владеть навыками учебно-исследовательской и проектной деятельности, навыками разрешения проблем; <br>- выявлять причинно-следственные связи и актуализировать задачу, выдвигать гипотезу ее решения, находить аргументы для доказательства своих утверждений, задавать параметры и критерии решения; <br>- анализировать полученные в ходе решения задачи результаты, критически оценивать их достоверность, прогнозировать изменение в новых условиях; <br>- уметь переносить знания в познавательную и практическую области жизнедеятельности;<br>- уметь интегрировать знания из разных предметных областей; <br>- выдвигать новые идеи, предлагать оригинальные подходы и решения; <br>- способность их использования в познавательной и социальной практике </td>\n<td>ПРб 2. Владение современными технологиями укрепления и сохранения здоровья, поддержания работоспособности, профилактики заболеваний, связанных с учебной и производственной деятельностью; <br>ПРб 4. владение физическими упражнениями разной функциональной направленности, использование их в режиме учебной и производственной деятельности с целью профилактики переутомления и сохранения высокой работоспособности; <br>ПРб 5. Владение техническими приемами и двигательными действиями базовых видов спорта, активное применение их в физкультурно-оздоровительной и соревновательной деятельности, в сфере досуга, в профессионально-прикладной сфере;</td>\n</tr>\n<tr>\n<td>ОК 04. Эффективно взаимодействовать и работать в коллективе и команде</td>\n<td>- готовность к саморазвитию, самостоятельности и самоопределению;<br>-овладение навыками учебно-исследовательской, проектной и социальной деятельности;<br>Овладение универсальными коммуникативными действиями:<br>б) совместная деятельность:<br>- понимать и использовать преимущества командной и индивидуальной работы;<br>- принимать цели совместной деятельности, организовывать и координировать действия по ее достижению: составлять план действий, распределять роли с учетом мнений участников обсуждать результаты совместной работы;<br>- координировать и выполнять работу в условиях реального, виртуального и комбинированного взаимодействия;<br>- осуществлять позитивное стратегическое поведение в различных ситуациях, проявлять творчество и воображение, быть инициативным<br>Овладение универсальными регулятивными действиями:<br>г) принятие себя и других людей:<br>- принимать мотивы и аргументы других людей при анализе результатов деятельности;<br>- признавать свое право и право других людей на ошибки;<br>- развивать способность понимать мир с позиции другого человека</td>\n<td>ПРб 4. владение физическими упражнениями разной функциональной направленности, использование их в режиме учебной и производственной деятельности с целью профилактики переутомления и сохранения высокой работоспособности; <br>ПРб 5. Владение техническими приемами и двигательными действиями базовых видов спорта, активное применение их в физкультурно-оздоровительной и соревновательной деятельности, в сфере досуга, в профессионально-прикладной сфере</td>\n</tr>\n<tr>\n<td>ОК 08 Использовать средства физической культуры для сохранения и укрепления здоровья в процессе профессиональной деятельности и поддержания необходимого уровня физической подготовленности</td>\n<td>готовность к саморазвитию, самостоятельности и самоопределению;<br>наличие мотивации к обучению и личностному развитию;<br>В части физического воспитания:<br>- сформированность здорового и безопасного образа жизни, ответственного отношения к своему здоровью;<br>- потребность в физическом совершенствовании, занятиях спортивно-оздоровительной деятельностью;<br>- активное неприятие вредных привычек и иных форм причинения вреда физическому и психическому здоровью;<br>Овладения универсальными регулятивными действиями:<br>- самостоятельно составлять план решения проблемы с учётом имеющихся ресурсов, собственных возможностей и предпочтений;<br>- давать оценку новым ситуациям;<br>- расширять рамки учебного предмета на основе личных предпочтений;<br>- делать осознанный выбор, аргументировать его, брать ответственность за решение;<br>- оценивать приобретённый опыт;<br>- способствовать формированию и проявлению широкой эрудиции в разных областях знаний; <br>- постоянно повышать свой образовательный и культурный уровень;</td>\n<td>ПРб 1. Умение использовать разнообразные формы и виды физкультурной деятельности для организации здорового образа жизни, активного отдыха и досуга, в том числе в подготовке к выполнению нормативов Всероссийского физкультурно-спортивного комплекса &quot;Готов к труду и обороне&quot; (ГТО); <br>ПРб 2. Владение современными технологиями укрепления и сохранения здоровья, поддержания работоспособности, профилактики заболеваний, связанных с учебной и производственной деятельностью; <br>ПРб 3. Владение основными способами самоконтроля индивидуальных показателей здоровья, умственной и физической работоспособности, динамики физического развития и физических качеств; <br>ПРб 4. владение физическими упражнениями разной функциональной направленности, использование их в режиме учебной и производственной деятельности с целью профилактики переутомления и сохранения высокой работоспособности; <br>ПРб 5. Владение техническими приемами и двигательными действиями базовых видов спорта, активное применение их в физкультурно-оздоровительной и соревновательной деятельности, в сфере досуга, в профессионально-прикладной сфере;<br>ПРб 6. Положительную динамику в развитии основных физических качеств (силы, быстроты, выносливости, гибкости и ловкости)</td>\n</tr>\n</table>\n<p>2. Структура и содержание общеобразовательной дисциплины</p>\n<p><strong>2.1. Объем дисциплины и виды учебной работы</strong></p>\n<table>\n<tr>\n<th>Вид учебной работы</th>\n<th>Объем в часах</th>\n</tr>\n<tr>\n<td>Объем образовательной программы дисциплины</td>\n<td>72</td>\n</tr>\n<tr>\n<td>самостоятельная работа</td>\n<td>4</td>\n</tr>\n<tr>\n<td>в т. ч.</td>\n<td></td>\n</tr>\n<tr>\n<td>Основное содержание</td>\n<td>66</td>\n</tr>\n<tr>\n<td colspan=\"2\">в т. ч.:</td>\n</tr>\n<tr>\n<td>теоретическое обучение</td>\n<td>4</td>\n</tr>\n<tr>\n<td>практические занятия </td>\n<td>62</td>\n</tr>\n<tr>\n<td>Профессионально-ориентированное содержание (содержание прикладного модуля)</td>\n<td>4</td>\n</tr>\n<tr>\n<td>в т. ч.:</td>\n<td></td>\n</tr>\n<tr>\n<td>теоретическое обучение</td>\n<td></td>\n</tr>\n<tr>\n<td>практические занятия </td>\n<td>4</td>\n</tr>\n<tr>\n<td>Промежуточная аттестация (экзамен)</td>\n<td>2</td>\n</tr>\n</table>\n<p><strong>2.2. Тематический план и содержание дисциплины </strong></p>\n<table>\n<tr>\n<th>Наименование разделов и тем</th>\n<th>Содержание учебного материала (основное и профессионально-ориентированное), лабораторные и практические занятия, прикладной модуль (при наличии)</th>\n<th>Объем часов</th>\n<th>Формируемые компетенции</th>\n</tr>\n<tr>\n<td>1</td>\n<td>2</td>\n<td>3</td>\n<td>4</td>\n</tr>\n<tr>\n<td colspan=\"2\">1 семестр </td>\n<td>24</td>\n<td></td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 1. Теоретические занятия.</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Тема 1.1. <br>Современное состояние физической культуры и спорта. Здоровье и здоровый образ жизни</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Физическая культура как часть культуры общества и человека. Роль физической культуры в общекультурном, профессиональном и социальном развитии человека. Современное представление о физической культуре: основные понятия; основные направления развития физической культуры в обществе и их формы организации</td>\n</tr>\n<tr>\n<td>Всероссийский физкультурно-спортивный комплекс «Готов к труду и обороне» (ГТО) — программная и нормативная основа системы физического воспитания населения, история и развитие комплекса «Готов к труду и обороне». Характеристика нормативных требований для обучающихся СПО</td>\n</tr>\n<tr>\n<td>Здоровье как базовая ценность человека и общества. Характеристика основных компонентов здоровья, их связь с занятиями физической культуры. Факторы, определяющие здоровье. Психосоматические заболевания</td>\n</tr>\n<tr>\n<td>Понятие «здоровый образ жизни» и его составляющие: режим труда и отдыха, профилактика и устранение вредных привычек, оптимальный двигательный режим, личная гигиена, закаливание, рациональное питание</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 2. Практические занятия. Учебно-тренировочные занятия</td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 2.1. <br>Лёгкая атлетика </td>\n<td>Содержание учебного материала</td>\n<td>8</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n<td>8</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях легкой атлетикой. Техника бега высокого и низкого старта, стартового разгона, финиширования. 1000м<br>Совершенствование техники спринтерского бега.100м<br>Совершенствование техники (кроссового бега, средние и длинные дистанции (2 000 м (девушки) и 3 000 м (юноши))<br>Совершенствование техники эстафетного бега (4 *100 м, 4*400 м; бега по прямой с различной скоростью)<br>Совершенствование техники прыжка в длину с разбега<br>Совершенствование техники прыжка в длину с места <br>Совершенствование техники метания гранаты весом 500 г (девушки) и 700 г (юноши); <br>Развитие физических способностей средствами лёгкой атлетики Подвижные игры и эстафеты с элементами легкой атлетики.</td>\n<td></td>\n</tr>\n<tr>\n<td>1. Техника безопасности на занятиях по легкой атлетике.  Техникой бега по прямой. Ознакомление с техникой метания гранаты. Зачет: Бег 100 м<br>Техника безопасности. Виды травм и их профилактика. Бег. СБУ. ОРУ. Техника бега по прямой. Техника низкого старта, выбегание со старта. Техника стартового разгона. Техника метания гранаты. Бег 100м.Бег по дорожкам, финиширование. Прыжки в длину с разбега: подбор шага, отталкивание, полет, приземление</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Техника эстафетного бега: передача эстафетной палочки. Бег 100 м. Зачет: Бег 1000 м<br>Техника безопасности. Бег. ОРУ. СБУ. Техника передачи эстафетной палочки, способы передачи. Техника передачи эстафетной палочки в «коридоре». Бег 100м. Передача эстафетной палочки. Техника эстафетного бега в команде (4×100м.). Бег по виражу. Как работает секундомер на старте и на финише. Работа судей на дистанции и на финише <br>Техника прыжков в длину с места. Техника подготовительной фазы прыжка с места. Техника фазы отталкивания прыжка с места. Техника фазы приземления прыжка с места. Выполнение прыжков в длину с места, прорабатывание каждого элемента.  Техника бега на 400 м.</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Техника бега с низкого старта. Совершенствование прыжков в длину с разбега. Зачет: Бег 800 м<br>Техника безопасности. Бег. Скоростно-прыжковые упражнения.  Техника выбегания с низкого старта. Техника финиширования. Техника прыжка в длину с разбега. Техника приземления на обе ноги. Техника бега на 800 метров</td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Техника прыжков в длину с разбега. Бег 800 м. Зачет: 2 км (д), 3 км (ю)<br>Техника безопасности. Бег. ОРУ на ягодицы. Техника бега на 800м. Вхождение в вираж. Техника прыжков в длину с разбега, перечислить ошибки. Техника прыжка в длину с места.<br>Бег 1000 м.  в медленном темпе</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.2.Волейбол </td>\n<td>Содержание учебного материала</td>\n<td>12</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n<td>12</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях волейболом. Освоение и совершенствование техники выполнения приёмов игры: стойки игрока, перемещения, передача мяча, подача, нападающий удар, прием мяча снизу двумя руками, прием мяча одной рукой с последующим нападением и перекатом в сторону, на бедро и спину, прием мяча одной рукой в падении.<br>Освоение/совершенствование приёмов тактики защиты и нападения.<br>Выполнение технико-тактических приёмов в игровой деятельности</td>\n<td></td>\n</tr>\n<tr>\n<td>1.Знакомство с правилами игры. Совершенствование стоек и перемещений волейболиста. Учебная игра. Зачет: Передача мяча у стены двумя руками сверху, снизу<br>Виды травм и их профилактика. Ходьба, бег, бег с заданием. ОРУ. Техника безопасности с волейбольным мячом. Стойка волейболиста. Техника передач волейбольного мяча сверху (работа у стенки и в парах).  <br>Техника передач волейбольного мяча снизу (работа у стенки и в парах).  Зачет: Передача мяча у стены двумя руками сверху и снизу. Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Совершенствование техники верхнего приема стоя на месте и после перемещения. Учебная игра. Зачет: Передача мяча в парах, двумя руками сверху, снизу<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Стойка волейболиста. Владение техническими приемами. Зачет: Передача мяча в парах, двумя руками снизу.  Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Совершенствование   верхнего приема в движении. Учебная игра. Зачет: Прием мяча над собой двумя руками, передача двумя руками сверху партнеру<br>Техника безопасности при работе с мячами. Ходьба, бег, бег с заданием. ОРУ. Совершенствование верхнего приема в движении. Подача мяча верхняя, нижняя.  Прием мяча над собой в кругу двумя руками сверху. Учебная игра Зачет: Прием мяча над собой двумя руками, передача двумя руками сверху партнеру. </td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Дальнейшее совершенствование верхнего, нижнего приема волейбольного мяча. Общефизическая подготовка. Учебная игра. Заполнение протокола. Зачет: над собой в кругу двумя руками сверху, снизу<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Дальнейшее совершенствование верхнего, нижнего приема волейбольного мяча.  Зачет: над собой в кругу двумя руками сверху. Выполнить подачу мяча посредством учебной игры.  Зачет: над собой в кругу двумя руками снизу. Заполнение протокола игры</td>\n<td>2</td>\n</tr>\n<tr>\n<td>5.Совершенствование передач сверху, снизу после перемещения, с изменением направления. Приемы мяча с подачи, вторая передача мяча в зоне 2 и 4. Учебная игра. Зачет: Верхняя подача. Нижняя подача<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Дальнейшее знакомство с правилами. Совершенствование передач сверху, снизу после перемещения, с изменением направления. Прием мяча с подачи, вторая передача мяча в зоне 2 и 4. Совершенствование техники передачи мяча сверху, снизу, в более сложных условиях. Обучение перебиванию мяча через сетку кулаком в прыжке. Прием мяча двумя руками сверху, попадание в баскетбольный щит из 10 попыток. Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>6.Совершенствование перебивания мяча через сетку кулаком в прыжке. ОРУ. Учебная игра. Зачет: Упражнения в тройках: прием и передача двумя руками сверху с передвижением<br>Техника безопасности с волейбольным мячом. Ходьба, бег, бег с заданием. ОРУ. Совершенствование приемов мяча сверху, снизу (стоя на месте и после перемещений, с подачи). Совершенствование перебивания мяча через сетку кулаком в прыжке. Упражнения в четверках через сетку. Учебная игра Закрепление всех изученных приемов посредством учебной игры. Заполнение протокола. Судейство.</td>\n<td>2</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 3. Практические занятия. Профессионально ориентированное содержание</td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 3.1. Составление и проведение комплексов упражнений для различных форм организации занятий физической культурой при решении профессионально-ориентированных задач</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Освоение методики составления и проведения комплексов упражнений для производственной гимнастики, комплексов упражнений для профилактики профессиональных заболеваний с учётом специфики будущей профессиональной деятельности. Освоение методики составления и проведения комплексов упражнений для профессионально-прикладной физической подготовки с учётом специфики будущей профессиональной деятельности. Характеристика профессиональной деятельности: группа труда, рабочее положение, рабочие движения, функциональные системы, обеспечивающие трудовой процесс, внешние условия или производственные факторы, профессиональные заболевания. Освоение комплексов упражнений для производственной гимнастики различных групп профессий (первая, вторая, третья, четвертая группы профессий)</td>\n</tr>\n<tr>\n<td colspan=\"2\">2 семестр </td>\n<td>48</td>\n<td></td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 1. Теоретические занятия.</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Тема 1.1. <br>Современное состояние физической культуры и спорта. Здоровье и здоровый образ жизни</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Общие представления об истории и развитии популярных систем оздоровительной физической культуры, их целевая ориентация и предметное содержание. Представления о современных системах и технологиях укрепления и сохранения здоровья (дыхательная гимнастика, антистрессовая гимнастика, глазодвигательная гимнастика, суставная гимнастика, оздоровительная ходьба, северная или скандинавская ходьба и оздоровительный бег и др.)<br>Особенности организации и проведения занятий в разных системах оздоровительной физической культуры и их функциональная направленность Формы организации самостоятельных занятий оздоровительной физической культурой и их особенности; соблюдение требований безопасности и гигиенических норм и правил во время занятий физической культурой</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 2. Профессионально ориентированное содержание</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Тема 2.1. <br>Подбор упражнений, составление и проведение комплексов упражнений для различных форм организации занятий физической культурой</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Освоение методики составления и проведения комплексов упражнений утренней зарядки, физкультминуток, физкультпауз, комплексов упражнений для коррекции осанки и телосложения<br>Освоение методики составления и проведения комплексов упражнений различной функциональной направленности</td>\n</tr>\n<tr>\n<td>В том числе самостоятельная работа <br>Составить комплекс ОРУ</td>\n<td>2</td>\n</tr>\n<tr>\n<td colspan=\"2\">Раздел 2. Практические занятия. Учебно-тренировочные занятия</td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 2.2.<br>Баскетбол</td>\n<td>Содержание учебного материала</td>\n<td>18</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n<td>18</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях баскетболом. Освоение и совершенствование техники выполнения приёмов игры:<br>перемещения, остановки, стойки игрока, повороты; ловля и передача мяча двумя и одной рукой, на месте и в движении, с отскоком от пола;  ведение мяча на месте, в движении, по прямой с изменением скорости, высоты отскока и направления, по зрительному и слуховому сигналу; броски одной рукой, на месте, в движении, от груди, от плеча; бросок после ловли и после ведения мяча, бросок мяча. Освоение и совершенствование приёмов тактики защиты и нападения. Выполнение технико-тактических приёмов в игровой деятельности</td>\n<td></td>\n</tr>\n<tr>\n<td>1.Техника безопасности. Правила в баскетболе. Ведение, передача мяча. Вырывания, выбивания мяча. Зачет: Вырывание, выбивание. Штрафной бросок<br>Техника безопасности при работе с баскетбольным мячом. Ходьба, бег, бег с заданием. ОРУ. Правила в баскетболе. Передача мяча: двумя руками сверху, двумя руками снизу, двумя руками от груди, двумя руками из- за головы, правой, левой от плеча. Ведение правой, левой рукой, разноименной, передача мяча от груди, с отскоком от пола.   Зачет: Вырывание, выбивание мяча. Штрафные броски. Игра 10 передач<br> Передача мяча: двумя руками сверху, двумя руками снизу, двумя руками от груди, двумя руками из- за головы, правой, левой от плеча. Ведение правой, левой рукой, разноименной, передача мяча от груди, с отскоком от пола. </td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Ознакомление с обманными действиями. Броски мяча в кольцо. Тактика игры. Учебная игра.   Зачет: Ведение двух мячей на месте и в движении. Броски с 6 точек</td>\n<td>4</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Передача мяча: двумя руками сверху, двумя руками снизу, одной рукой снизу, одной рукой над головой, двумя руками от груди, двумя руками из- за головы, правой левой от плеча. Ведение двух мячей на месте и вдвижении.  Обманные действия. Тактика игры. Броски мяча в кольцо. Ведение, два шага, атака на щит. Броски с 6 точек за 1 минуту. Учебная игра. Игра «-5»</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Передача мяча. Обманные действия. Тактика игры. Броски мяча в кольцо. Ведение, два шага, атака на щит. Броски с 6 точек за 1 минуту.  Зачет: Ведение двух мячей на месте и в движении.  Броски с 6 точек. Учебная игра. Игра «-5»</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Обманные действия. Повторение техники игры в защите, в нападении. Учебная игра.    Зачет: Ведение два шага, атака на щит</td>\n<td>4</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Передача мяча: двумя руками сверху, двумя руками снизу, одной рукой снизу, одной рукой над головой, двумя руками от груди, двумя руками из- за головы, правой левой от плеча. Обманные действия.  Повторение техники игры в защите, в нападении. Передвижение в двойках, атака на щит. Ведение два шага, атака на щит. Учебная игра. Игра «33».</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Передача мяча. Обманные действия.  Повторение техники игры в защите, в нападении. Передвижение в двойках, атака на щит.  Зачет: Ведение два шага, атака на щит. Учебная игра. Игра «33».</td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Совершенствование ловли мяча: двумя руками от груди, с отскоком от пола. Учебная игра, судейство. Зачет: Передвижение в двойках, атака на щит</td>\n<td>4</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Ведение правой, левой рукой, передача мяча правой, левой, от груди, с отскоком от пола. Совершенствование ловли мяча: двумя руками от груди, с отскоком от пола. Передвижение в тройках, атака на щит. Передвижение в двойках, атака на щит.  Учебная игра. «Стритбол». Судейство </td>\n<td>2</td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Ведение правой, левой рукой, передача мяча правой, левой, от груди, с отскоком от пола. Совершенствование ловли мяча: двумя руками от груди, с отскоком от пола. Зачет: Передвижение в двойках, атака на щит.  Учебная игра. «Стритбол». Судейство </td>\n<td>2</td>\n</tr>\n<tr>\n<td>5.Тактика игры в защите. Личная защита. Двухсторонняя игра. Заполнение протокола судейства. Штрафной бросок. Судейство. Зачет: Передвижение в тройках, атака на щит</td>\n<td>4</td>\n</tr>\n<tr>\n<td></td>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Ведение, передача мяча.  Ведение правой, левой рукой, передача мяча правой, левой, от груди, с отскоком от пола.  Тактика игры в защите. Личная защита. Штрафной бросок (правила назначения штрафного броска за фолы и нарушения).  Передвижение в тройках, атака на щит. Заполнение протокола судейства. Двусторонняя игра</td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td>2)Ходьба, бег, бег с заданием. ОРУ.  Ведение, передача мяча. Тактика игры в защите. Личная защита. Штрафной бросок. Зачет: Передвижение в тройках, атака на щит. Заполнение протокола судейства. Двусторонняя игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td></td>\n<td>В том числе самостоятельная работа<br>Заполнение протокола </td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td>Тема 2.3. Основная гимнастика </td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04, <br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях гимнастикой. <br>Выполнение строевых упражнений, строевых приёмов: построений и перестроений, передвижений, размыканий и смыканий, поворотов на месте. <br>Выполнение общеразвивающих упражнений без предмета и с предметом; в парах, в группах, на снарядах и тренажерах.<br>Выполнение прикладных упражнений: ходьбы и бега, упражнений в равновесии, лазанье и перелазание, метание и ловля, поднимание и переноска груза, прыжки</td>\n</tr>\n<tr>\n<td>1.Техника безопасности на занятиях. Упражнения на укрепление мышц живота. Комплекс упражнений на гимнастической скамейке. Отягощения. Зачет: Упражнение «Циркуль»<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ на гибкость. Упражнения на гимнастических ковриках для развития мышц плечевого пояса, косых, боковых мышц спины. Закрепить комплекс на гимнастической скамейке по ширине спортивного зала. Выполнение комплекса, прорабатывание каждого элемента. Упражнения с грифом, «блинами». Отягощения</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.4. Акробатика</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04, <br>ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Освоение акробатических элементов: кувырок вперед, кувырок назад, длинный кувырок, кувырок через плечо, стойка на лопатках, мост, стойка на руках, стойка на голове и руках, переворот боком «колесо», равновесие «ласточка». Совершенствование акробатических элементов. Освоение и совершенствование акробатической комбинации (последовательность выполнения элементов в акробатической комбинации может изменяться):</td>\n</tr>\n<tr>\n<td>1.Упражнения в паре. Упражнения для мышц плечевого пояса, косых, боковых мышц спины. Техника кувырка вперед, работа над ошибками. Зачет: «Ласточка». Кувырок вперед. Стойка на лопатках<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ в парах. Упражнения для мышц плечевого пояса, косых, боковых мышц спины. Техника кувырка вперед, ласточка, стояка на лопатках, работа над ошибками</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.5 <br>Атлетическая гимнастика</td>\n<td>Содержание учебного материала</td>\n<td>4</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Выполнение упражнений и комплексов упражнений атлетической гимнастики для рук и плечевого пояса, мышц спины и живота, мышц ног с использованием собственного веса. Выполнение упражнений со свободными весами. Выполнение упражнений и комплексов упражнений с использованием новых видов фитнесс оборудования. Выполнение упражнений и комплексов упражнений на силовых тренажерах</td>\n</tr>\n<tr>\n<td>1.Общеразвивающие упражнения в парах. Упражнение на эспандере «колесико» Зачет: Пистолет на каждую ногу<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ в парах, упражнения с собственным весом. Упражнение на эспандере «колесико».  Виды травм и их профилактика. Игра в волейбол. Подготовка к выполнению нормативов Всероссийского физкультурно-спортивного комплекса «Готов к труду и обороне» (ГТО). Игра в волейбол</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Упражнения с гантелями, с собственным весом. Приседания с блинами.  Зачет: Приседания через скамейку в паре<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ с собственным весом. Упражнения с гантелями. Приседание с «блином»<br>Круговая тренировка:<br>-скакалка;<br>-гимнастическая скамейка;<br>-работа с обручами; <br>-планка малая; <br>-планка большая.</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.6.<br>Бадминтон</td>\n<td>Содержание</td>\n<td>10</td>\n<td>ОК 01, ОК 04,<br>ОК 08</td>\n</tr>\n<tr>\n<td>Техника выполнения приёмов игры: основные стойки, классическая универсальная хватка ракетки, техника ударов, перемещения игрока, подачи, удары по волану техника передвижения игрока к сетке, в стороны, назад. Тактика игры в бадминтон: тактика защиты, тактика нападения. Правила игры. Игра по упрощенным правилам на площадках разных размеров. Игра по правилам. Подвижные игры и эстафеты с элементами бадминтона. Техника безопасности на занятиях бадминтоном</td>\n<td>10</td>\n</tr>\n<tr>\n<td>В том числе практических занятий</td>\n</tr>\n<tr>\n<td>Освоение и совершенствование техники выполнения приёмов игры. Освоение и совершенствование приёмов тактики защиты и нападения. Выполнение технико-тактических приёмов в игровой деятельности. Развитие физических способностей средствами бадминтона</td>\n</tr>\n<tr>\n<td>1.Разучивание способов хвата ракетки, основной стойки бадминтониста. Разучивание ударов по волану.  Зачет: Набивание волана (жонглирование) попеременно открытой и закрытой стороной ракетки<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ.  Разучивание способов хвата ракетки, основной стойки бадминтониста. Разучивание ударов по волану. Разучивание подачи и удара в упрощенных условиях. Движения, имитации справа, слева. Учебная игра в парах</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Закрепить хват ракетки. Формировать умение владеть воланом (чувство волана). Отрабатывать стойку бадминтониста.  Зачет: Выполнение короткой подачи закрытой, открытой стороной ракетки.<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ с воланом и ракеткой. Закрепить хват ракетки. Формировать умение владеть воланом (чувство волана). Отрабатывать стойку бадминтониста. Выполнение короткой подачи закрытой, открытой стороной ракетки в паре и через сетку. Зачет: Выполнение короткой подачи закрытой, открытой стороной ракетки. Учебная игра в парах</td>\n<td>2</td>\n</tr>\n<tr>\n<td>3.Разучивание подачи и удара в упрощенных условиях. Зачет: Работа в паре верхний нижний прием.</td>\n<td>2</td>\n</tr>\n<tr>\n<td>1)Техника безопасности. Ходьба, бег, бег с заданием. ОРУ с воланом и ракеткой.  Ознакомить с техникой подачи и ударов. Отрабатывать стойку бадминтониста. Зачет: Работа в паре верхний прием. Учебная игра в парах, в четверках </td>\n<td>2</td>\n</tr>\n<tr>\n<td>4.Ознакомление с атакующим ударом. Судейство, ведение протокола.  Зачет: Работа в паре верхний, нижний прием через сетку. <br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Ознакомление с атакующим ударом. Удары по волану. Зачет: Работа в паре верхний прием через сетку.  Судейство. Ведение протокола. Учебная игра в парах, в четверках</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.7 Теннис</td>\n<td>Содержание </td>\n<td>4</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Техника выполнения приёмов игры: упражнения с мячом - «школа мяча»; способы хватки ракетки (для удара справа, слева, универсальная хватка); упражнения с ракеткой; упражнения с ракеткой и мячом. Технические элементы: удары по мячу, перемещения по площадке, передвижения игрока (старт из исходного положения, движение к мячу, «вход» в удар, «выход» из удара и повторный старт, выход на позицию наивысшей готовности для следующего ответа); подача, приём подачи (свеча). Тактика игры в теннис: тактика защиты, тактика нападения. Правила игры. Игра по упрощенным правилам. Игра по правилам. Подвижные игры и эстафеты с элементами тенниса. Техника безопасности на занятиях теннисом.</td>\n<td></td>\n</tr>\n<tr>\n<td>В том числе практических занятий</td>\n<td></td>\n</tr>\n<tr>\n<td>Освоение и совершенствование техники выполнения приёмов игры. Освоение и совершенствование приёмов тактики защиты и нападения. Выполнение технико-тактических приёмов в игровой деятельности. Развитие физических способностей средствами тенниса</td>\n<td></td>\n</tr>\n<tr>\n<td>1.Техника безопасности. Обучение и закрепление приема мяча с подачи. Подача справа и слева накатом. Правила игры. Ведение протокола. Зачет: Подача мяча справа из 10 попыток<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Обучение и закрепление приема мяча с подачи. Подача справа и слева накатом. Подача мяча справа из 10 попыток. Зачет: Подача мяча справа из 10 попыток.  Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>2.Закрепление и совершенствование приема мяча с подачи. Судейство. Учебная игра.  Зачет: Подача мяча слева из 10 попыток<br>Техника безопасности. Ходьба, бег, бег с заданием. ОРУ. Закрепление и совершенствование приема мяча с подачи. Подача мяча слева из 10 попыток. Судейство. Учебная игра</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Тема 2.8. Футбол</td>\n<td>Содержание учебного материала</td>\n<td>2</td>\n<td>ОК 01, ОК 04,<br> ОК 08</td>\n</tr>\n<tr>\n<td>Практические занятия</td>\n</tr>\n<tr>\n<td>Техника безопасности на занятиях футболом. Освоение и совершенствование техники выполнения приёмов игры: удар по мячу носком, серединой подъема, внутренней, внешней частью подъема; остановки мяча внутренней стороной стопы; остановки мяча внутренней стороной стопы в прыжке, остановки мяча подошвой. Правила игры и методика судейства. Техника нападения. Действия игрока без мяча: освобождение от опеки противника.  Освоение/совершенствование приёмов тактики защиты и нападения.<br>Выполнение технико-тактических приёмов в игровой деятельности (учебная игра)</td>\n</tr>\n<tr>\n<td colspan=\"2\">Промежуточная аттестация по дисциплине (экзамен)</td>\n<td>2</td>\n<td></td>\n</tr>\n<tr>\n<td colspan=\"2\">Всего:</td>\n<td>72</td>\n<td></td>\n</tr>\n</table>\n<p>3. Условия реализации программы общеобразовательной дисциплины</p>\n<p>3.1. Для реализации программы дисциплины предусмотрены спортивные сооружения:</p>\n<p>спортивный зал, оснащенный спортивным инвентарём и оборудованием, обеспечивающим достижение результатов освоения дисциплины;</p>\n<p>оборудованные открытые спортивные площадки, обеспечивающие достижение результатов освоения дисциплины;</p>\n<p>Перечень оборудования и инвентаря спортивных сооружений:</p>\n<p><strong>Спортивные игры</strong></p>\n<p>Щит баскетбольный игровой (комплект), кольца баскетбольные, табло игровое, мяч баскетбольный №7 массовый, мяч баскетбольный №7 для соревнований, мяч баскетбольный №5 массовый, мяч футбольный №4 массовый, мяч футбольный №5 массовый, мяч футбольный №5 для соревнований, насос для накачивания мячей с иглой, жилетки игровые.</p>\n<p><strong>Гимнастика</strong></p>\n<p>Скамейка гимнастическая, комплект матов гимнастических, гимнастическая скамейка.</p>\n<p><strong>Легкая атлетика</strong></p>\n<p>Секундомер, граната для метания, эстафетная полочка. </p>\n<p><strong>Оборудование для проведения соревнований</strong></p>\n<p>Скамейка, сантиметр мерный, комплект для соревнований (форма), персональный компьютер (ведение мониторингов и иных документов)</p>\n<p><strong>Прочее</strong></p>\n<p>Аптечка медицинская.</p>\n<p><strong>Открытые спортивные площадки:</strong></p>\n<p> ворота футбольные, сетки для футбольных ворот, мячи футбольные, стартовые флажки, флажки красные и белые, палочки эстафетные, нагрудные номера, секундомеры.</p>\n<p><strong>3.2. Информационное обеспечение реализации программы</strong></p>\n<p>Библиотечный фонд образовательной организации имеет печатные и электронные образовательные и информационные ресурсы.</p>\n<p><strong>3.2.1. Основные печатные издания</strong></p>\n<ul>\n<li>Физическая культура (базовый уровень)», Андрюхина Т.В., Третьякова Н.В. /Под ред. Виленского М.Я. – ООО «Русское слово», 2019 г.</li>\n<li>Физическая культура. 10-11 классы: учебник для общеобразоват. организаций: базовый уровень / А.П. Матвеев. — М.: Просвещение, 2019. — 319 с.</li>\n<li>Физическая культура. 10-11 классы: Учебник для общеобразоват. учреждений / Г.И. Погадаев. — М.: ДРОФА / Учебник, 2019. — 288 с.</li>\n<li>Физическая культура. 10-11 классы: Учебник для общеобразоват. учреждений / А.П. Матвеев, Е.С. Палехова. — М.: Вентана-Граф / Учебник, 2019. — 160 с.</li>\n</ul>\n<p><strong>3.2.2. Основные электронные издания </strong></p>\n<ul>\n<li>Баскетбол, волейбол: учебное пособие для вузов / Е. В. Конеева [и др.]; под редакцией Е. В. Конеевой. — 2-е изд., перераб. и доп. — Москва: Издательство Юрайт, 2024. — 176 с. — (Высшее образование). — ISBN 978-5-534-19017-5. — Текст: электронный // Образовательная платформа Юрайт [сайт]. — URL: https://urait.ru/bcode/555755 </li>\n<li>Легкая атлетика: учебное пособие для среднего профессионального образования / А. А. Зайцев, С. Я. Луценко. — 3-е изд., перераб. и доп. — Москва: Издательство Юрайт, 2024. — 70 с. — (Профессиональное образование). — ISBN 978-5-534-19950-5. — Текст: электронный // Образовательная платформа Юрайт [сайт]. — URL: https://urait.ru/bcode/557365 </li>\n</ul>\n<p><strong>3.2.3. Дополнительные источники </strong></p>\n<ul>\n<li>Теннис, настольный теннис, бадминтон: учебное пособие для вузов / Е. В. Конеева [и др.]; под общей редакцией Е. В. Конеевой. — 3-е изд., перераб. и доп. — Москва: Издательство Юрайт, 2024. — 95 с. — (Высшее образование). — ISBN 978-5-534-19051-9. — Текст: электронный // Образовательная платформа Юрайт [сайт]. — URL: https://urait.ru/bcode/555844</li>\n<li><strong>Физическая культура:10-11-е классы: учебник: издание в </strong><strong>pdf</strong><strong>-формате / А.П. Матвеев, </strong><strong>Е. С.</strong><strong> </strong><strong>Палехова</strong><strong>. -6-е изд.,</strong><strong> </strong><strong>стер</strong><strong>.-</strong><strong>Москва: </strong><strong>Просвещение</strong><strong>,</strong><strong> </strong><strong>2022.-158[2]</strong><strong> </strong><strong>c</strong><strong>.: </strong><strong>ил. </strong><strong>ISBN</strong><strong> 978-5-09-101692-5 </strong><strong>(</strong><strong>электр</strong><strong>. </strong><strong>Изд.).</strong><strong> - Текст электронный. </strong><strong>ISBN</strong><strong> 978-5-09-094658-2 (</strong><strong>печ</strong><strong>. </strong><strong>изд</strong><strong>). </strong><strong> </strong></li>\n<li>Контроль и оценка результатов освоения общеобразовательной дисциплины</li>\n</ul>\n<p><strong>Контроль</strong> <strong>и оценка</strong> результатов освоения общеобразовательной дисциплины раскрываются через дисциплинарные результаты, направленные на формирование общих и профессиональных компетенций по разделам и темам содержания учебного материала.</p>\n<table>\n<tr>\n<th>Общая/профессиональная компетенция</th>\n<th>Раздел/Тема</th>\n<th>Тип оценочных мероприятия</th>\n</tr>\n<tr>\n<td>ОК 01. Выбирать способы решения задач профессиональной деятельности применительно к различным контекстам</td>\n<td>Темы 1.1, 1.2 ,2.2,<br>3.1, 3.2, 3.3, 3.4, 3.5,<br>2.3, 2.4, 2.5, 2.6, 2.7, 2.8,2.9</td>\n<td>составление словаря терминов, либо кроссворда<br>защита презентации/доклада-презентации<br>выполнение самостоятельной работы<br>составление комплекса физических упражнений для самостоятельных занятий с учетом индивидуальных особенностей,<br>составление профессиограммы<br>заполнение дневника самоконтроля<br>защита реферата<br>составление кроссворда<br>фронтальный опрос<br>контрольное тестирование<br>составление комплекса упражнений<br>оценивание практической работы<br>тестирование<br>демонстрация комплекса ОРУ,<br>сдача контрольных нормативов<br>сдача контрольных нормативов (контрольное упражнение)<br>сдача нормативов ГТО<br>выполнение упражнений на дифференцированном зачете (экзамен)</td>\n</tr>\n<tr>\n<td>ОК 04. Эффективно взаимодействовать и работать в коллективе и команде</td>\n<td>Темы 1.1, 1.2 ,2.2,<br>3.1, 3.2, 3.3, 3.4, 3.5,<br>2.3, 2.4, 2.5, 2.6, 2.7, 2.8,2.9</td>\n</tr>\n<tr>\n<td>ОК 08. Использовать средства физической культуры для сохранения и укрепления здоровья в процессе профессиональной деятельности и поддержания необходимого уровня физической подготовленности</td>\n<td>Темы 1.1, 1.2 ,2.2,<br>3.1, 3.2, 3.3, 3.4, 3.5,<br>2.3, 2.4, 2.5, 2.6, 2.7, 2.8, 2.9</td>\n</tr>\n</table>','2026/02/pub_20260227_061135_15db0cf9.docx','РП ФИЗ-РА 09.02.01 К11 Закружная.docx',98688,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',4,'rabochaya-programma-distsipliny-fizicheskaya-kultura-1',NULL,NULL,30,0,'published',NULL,'auto_approved','2026-02-27 06:11:36',0.95,'pending','2026-02-27 06:11:36','2026-02-27 03:11:35','2026-03-04 09:23:14'),(18,1611,'Современные методы развития речи у младших школьников','Публикация описывает эффективные методы и приёмы развития речи у младших школьников, включая работу со словарём, игры со словами, словесное рисование, написание сочинений и другие. Особое внимание уделяется развитию словарного запаса и умению правильно использовать слова.','<p>Эффективные методы и приемы развития речи младших школьников</p>\n<p><strong>«Берегите наш язык , наш прекрасный русский язык,</strong><strong><br></strong><strong>этот клад, это достояние, переданное нам нашими предшественниками...</strong><strong><br></strong><strong>Обращайтесь почтительно с этим могущественным орудием,</strong><strong><br></strong><strong>в руках умелых оно в состоянии совершить чудеса».</strong><br>И.С.Тургенев</p>\n<p>Речь - это вид деятельности человека, представляющий собой реализацию мышления на основе использования средств языка (слов, словосочетаний, предложений). Речь выполняет функции общения, сообщения, эмоционального самовыражения и воздействия на других людей и является одним из важнейших показателей уровня культуры человека, его интеллекта. Формирование речи младших школьников - одна из важнейших задач, стоящих перед учителями. Развитая речь помогает ребенку лучше овладевать знаниями, формирует ум, волю, чувства. Работа по развитию речи активно должна вестись еще в дошкольном возрасте. О необходимости развивать речь ребенка, воспитывать у него любовь говорили лучшие педагоги и методисты. Важную роль в создании методики развития речи сыграла деятельность Е.И.Тихеевой, талантливого педагога, последовательницы К.Д.Ушинского, общественного деятеля в области дошкольного воспитания. Е.И.Тихеева была знакома с опытом детских садов России, Италии, с 1913 г. сама руководила детским садом. Вслед за К.Д.Ушинским она считала родной язык фоном, на котором развертывается все обучение и воспитание в детском саду и школе. Основное место в своей педагогической теории Е.И.Тихеева отводила методике развития речи.</p>\n<p>В младшем школьном возрасте ведущей деятельностью ребенка становится учебная деятельность. Качество и уровень развития речи ученика зависит от того, насколько богат его словарный запас и как развито умение правильно использовать слова для построения предложения и текста.</p>\n<p>В основе ФГОС НОО лежит системно-деятельностный подход, который предполагает развитие личности обучающегося на основе усвоения им универсальных учебных действий. Стандарт устанавливает требования к результатам освоения ООП, они носят личностный, предметный и метапредметный характер, их достижение предполагает высокий уровень развития как устной, так и письменной форм речи. Известно много методов и приемов по развитию речи младших школьников. Развивать речь - значит систематически работать над ее содержанием, последовательно учить детей построению предложений, вдумчивому выбору подходящего слова и его формы, постоянно работать над грамотным оформлением мыслей</p>\n<p>Научить ребенка ясно и грамматически правильно говорить, излагать собственные мысли и выражать эмоции, развивать умение общаться - сложное и кропотливое дело, требующее от учителя напряженного труда.</p>\n<p>Развитие речевой деятельности ребенка - не стихийный процесс, он требует определенного педагогического руководства. Большинство направлений работы по развитию речи можно успешно проводить на самых разных уроках и во внеурочной деятельности тоже. Но главные - это, конечно же, уроки русского языка и литературного чтения.</p>\n<p>Эффективные методы и приемы развития речи:</p>\n<p>Не обладая достаточным запасом слов, ученик не сможет построить предложения, выразить свою мысль. Учащиеся часто не понимают самых простых слов. Причиной этого является слабая работа по привитию навыка вникать в смысл слова. Для уточнения смысла слова эффективны такие всем известны задания, как назвать от какого слова образовались данные слова, подбор проверочных и однокоренных слов, поиск проверяемых и проверочных слов.</p>\n<p><strong>Работа со словарем-тетрадкой</strong>, в который записывают новые словарные слова определённым образом. Задания направлены не только на запоминание нового слова, но и ведется систематическая работа по развитию речи. Слова разбиты на блоки, у каждого блока свое название. Например: «Россия», «птицы» и т.д. Ребенок записывает слово, делит на слоги, ставит ударение и подбирает картинку или самостоятельно рисует цветными карандашами. Цвет дает возможность лучше запомнить словарное слово наизусть.Такие упражнения заставляют вникать в смысл слова, а также вырабатывать орфографический навык.</p>\n<p><strong>Игры со словами</strong> развивают у детей природное языковое чутье, подготавливают их к восприятию поэтических форм. Одна из таких игр - это подбор рифм к данным словам.</p>\n<p><strong>Словесное рисование</strong> - способность выражать свои мысли и чувства на основе прочитанной сказки, басни, рассказа, стихотворения.</p>\n<p><strong>Написание сочинений</strong>. Можно выделить разные виды сочинений. Сочинения-описания могут быть основаны на наблюдениях учащихся, на их личных впечатлениях или на анализе справочной и научно-популярной литературы.</p>\n<p><strong>Сочинения-рассказы</strong> представляют собой повествование о каких-то событиях. Они основаны на личном опыте учащихся.</p>\n<p>Сочинения-сказки наиболее интересный вид сочинений. Сказки не только кладезь народной мудрости, но и средство для развития учащихся: их творческих способностей, речи, воображения, фантазии, критического мышления. Написание сказок требует глубокого анализа смысла понятий. Ведь по ходу сказки героев нужно описать.</p>\n<p>Сочинения-загадки. Цель - описать объект, его свойства, чтобы его можно было узнать. Для этого ученику нужно выделить существенные свойства описываемого предмета. Затем дать ему словесную характеристику на естественном языке, не называя объект. При этом сочинение может быть построено в форме описания или сказки.</p>\n<p>Данные формы работы ориентированы на развитие творческих способностей, воображения, на формирование положительных эмоций в обучении.</p>\n<p><strong>Ребусы, кроссворды</strong>. Подбор синонимов, антонимов, омонимов. При использовании данных приёмов можно не только узнать много интересных вещей из разных областей культуры и науки, обогатить свой словарный запас, но и помочь себе развить свою собственную речь. Данные методы и приемы помогают в тренировке памяти и правописания.</p>\n<p><strong>Артикуляционные гимнастики</strong> - скороговорки, чистоговорки. Во время скороговорного общения школьники имеют возможность ощутить гордость за богатство своего языка, почувствовать силу русской речи, создать пространство творческого взаимодействия, порадовать друг друга и порадоваться самим.</p>\n<p><strong>Читательский дневник</strong>. На протяжении всего обучения в начальной школе дети ведут читательские дневники, где фиксируют число выполненной работы, автора и название прочитанного произведения, затраченное время работы. В этом дневнике записывают свои рассуждения о прочитанном произведении, показывая свое отношение к главным героям.</p>\n<p>Упражнения по развитию речи имеют место на каждом уроке и не могут быть ограничены только уроками русского языка и литературы. Каждый устный ответ ученика является упражнением в устной речи и, следовательно, он должен отвечать требованиям к содержанию, построению и оформлению речевого высказывания.</p>\n<p><strong>Работа над словосочетанием и предложением</strong> предусматривает упражнения на основе образца (чтение предложений, их анализ); конструктивные (нахождение границ предложений в тексте, написанном без точек и заглавных букв, распознавание грамматической основы слова с помощью вопросов, выражение одной мысли в нескольких вариантах предложений); творческие (составление словосочетаний и предложений по иллюстрации, по данным словам и др.);</p>\n<p>Учитель начальных классов нередко испытывает затруднения при попытках развить воображение и речь детей, в том числе и посредством словесного рисования. Словесное рисование - это способность человека выражать свои мысли и чувства на основе прочитанной сказки, басни, рассказа, стихотворения.</p>\n<p><strong>Список литературы</strong></p>\n<ul>\n<li>Артюхова И. Устойчивость внимания // Нач. шк. (приложение). - 2002.- №8.</li>\n<li>Бетенькова Н.М. Орфография, грамматика - в рифмовках занимательных. - М.: Просвещение, 1995, с.85-87.</li>\n<li>Варова Т.В. Самоконтроль в работе над грамотностью. Алгоритм поиска и квалификации орфографической ошибки // Вестник. - 2003.- №11.</li>\n<li>Венгер А.Л. Психологическое консультирование и диагностика. - Интернет.</li>\n<li>Возрастные возможности усвоения знаний / Под ред. Д.Б.Эльконина, В.В.Давыдова. - М.: Просвещение, 1966.</li>\n<li>Вопросы психологии учебной деятельности младших школьников / Под ред. Д.Б.Эльконина, В.В.Давыдова. - М.: Издательство Академии педагогических наук.</li>\n</ul>','2026/02/pub_20260227_081016_35050195.docx','публикация.docx',18078,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',1,'sovremennye-metody-razvitiya-rechi-u-mladshih-shkolnikov',NULL,NULL,36,0,'published',NULL,'auto_approved','2026-02-27 08:10:17',0.95,'ready','2026-02-27 08:10:16','2026-02-27 05:10:16','2026-03-04 23:00:40'),(19,1622,'Профилактика злоупотребления ПАВ среди детей и подростков','Публикация рассматривает проблему злоупотребления психоактивными веществами среди детей и подростков, описывает факторы, способствующие этому, и предлагает основные направления профилактики. Особое внимание уделяется роли социального педагога в организации профилактических мероприятий.','<p><strong>Принципы разработки и основные направления мероприятий по профилактике ПАВ</strong></p>\n<p><strong>Введение</strong></p>\n<p>Проблема злоупотребления психоактивными веществами (ПАВ) среди детей и подростков является одной из острейших современных социальных проблем. Она негативно влияет на физическое и психическое здоровье молодёжи, снижая качество их жизни и ставя под угрозу будущее благополучия всего общества. Для эффективной борьбы с этой угрозой необходим комплексный подход, включающий активное взаимодействие всех заинтересованных сторон: родителей, учителей, психологов, медицинских работников и, безусловно, самих молодых людей.</p>\n<p><strong>Факторы распространения ПАВ среди молодёжи</strong></p>\n<p>Факторы, способствующие широкому распространению ПАВ среди несовершеннолетних, включают:</p>\n<ul>\n<li>Раннее знакомство с алкоголем и наркотическими препаратами;</li>\n<li>Доступность алкогольных напитков и запрещенных веществ в молодёжной среде;</li>\n<li>Низкое осознание вреда от приёма психоактивных веществ;</li>\n<li>Недостаточную физическую активность и отсутствие возможностей для полноценного культурного отдыха;</li>\n<li>Отсутствие достаточного контроля со стороны взрослых (родителей, преподавателей).</li>\n</ul>\n<p><strong>Основные направления профилактики</strong></p>\n<p>Предотвращение злоупотребления ПАВ включает три ключевых направления профилактических мер:</p>\n<p><strong>🔹</strong><strong> Первичная профилактика</strong></p>\n<p><strong>Цель:</strong> Предупреждение первого контакта с ПАВ и формирование устойчивых установок на ведение здорового образа жизни.</p>\n<p>Мероприятия первичной профилактики:</p>\n<ul>\n<li>Интерактивные лекции с участием врачей-наркологов и психологов, объясняющие опасность курения, алкоголя и наркотиков;</li>\n<li>Проведение тренингов по повышению самооценки, направленных на обучение уверенным действиям и сопротивлению негативному влиянию сверстников;</li>\n<li>Организация просветительских акций, включая спортивные состязания, фестивали и флешмобы, пропагандисты здоровые привычки (&quot;День отказа от сигарет&quot;);</li>\n<li>Конференции и круглых столов, где молодые люди встречаются с успешными представителями общества, вдохновляющими на активную жизнь и здоровое поведение;</li>\n<li>Обучающие игры и квесты, направленные на выработку умения отказывать в опасных ситуациях.</li>\n</ul>\n<p><strong>📌</strong><strong> Вторичная профилактика</strong></p>\n<p><strong>Цель:</strong> Выявление лиц, находящихся в группе риска, и оказание адресной помощи детям и подросткам, столкнувшимся с трудностями или потенциальной опасностью начала употребления ПАВ.</p>\n<p>Примеры вторичной профилактики:</p>\n<ul>\n<li>Индивидуальные консультации с педагогами-психологами и соцработниками для раннего выявления признаков отклоняющегося поведения;</li>\n<li>Группы поддержки, собирающиеся регулярно для обсуждения возникающих трудностей и выработки путей выхода из сложных ситуаций;</li>\n<li>Анонимные анкетирования, позволяющие оценить риск вовлечения подростка в употребление ПАВ;</li>\n<li>Семейные сессии и семинары, предназначенные для информирования родителей о возможных признаках начала злоупотребления и путях решения проблемы;</li>\n<li>Творческие проекты, привлекательные занятия музыкой, живописью и театром, способные переключить внимание подростков на позитивные виды активности.</li>\n</ul>\n<p><strong>⚠</strong><strong>️ Третичная профилактика</strong></p>\n<p><strong>Цель:</strong> Оказание специализированной помощи молодым людям, уже страдающим от зависимости.</p>\n<p>Действия третичной профилактики:</p>\n<ul>\n<li>Психотерапевтическая поддержка, включая индивидуальные и групповые сеансы терапии с квалифицированными специалистами;</li>\n<li>Реабилитационные программы и лагери, обеспечивающие восстановление физической и психологической гармонии участников;</li>\n<li>Образовательные курсы, направленные на профессиональное ориентирование и приобретение новых важных жизненных навыков;</li>\n<li>Клубы взаимопомощи, созданные бывшими зависимыми лицами, поддерживающие друг друга в стремлении сохранить трезвый образ жизни;</li>\n<li>Юридическая поддержка, направленная на защиту прав и законных интересов зависимых лиц.</li>\n</ul>\n<p><strong>Роль социального педагога в профилактике</strong></p>\n<p>Социальный педагог играет ключевую роль в организации и координации профилактических мероприятий против злоупотребления ПАВ среди школьников. Его обязанности включают:</p>\n<ul>\n<li>Анализ специфики образовательного учреждения и выявление особенностей окружающей среды, определение целевой аудитории для осуществления профилактических действий.</li>\n<li>Разработка специализированных программ профилактики совместно с администраторами учебных заведений, медицинскими работниками и психологами.</li>\n<li>Координация мероприятий, таких как лекции, беседы, классные часы, спортивные мероприятия и конкурсы, стимулирующих интерес к здоровому образу жизни.</li>\n<li>Работа с семьями, обеспечение консультационной поддержки родителям и рекомендациями по эффективному воспитанию и наблюдению за поведением ребёнка.</li>\n<li>Сотрудничество с медицинскими специалистами, такими как врачи-наркологи и терапевты, позволяющее оперативно реагировать на случаи появления тревожных симптомов.</li>\n<li>Привлечение добровольческих и некоммерческих организаций, расширяя ресурсную базу и увеличивая эффективность реализуемых профилактических инициатив.</li>\n<li>Оценка эффективности проведённой работы путём постоянного мониторинга и анализа полученных результатов.</li>\n</ul>\n<p><strong>Выводы</strong></p>\n<p>Эффективная профилактика злоупотребления ПАВ основывается на ряде важнейших принципов:</p>\n<ul>\n<li>Комплексность применяемых методов воздействия, включающих одновременно школьные, медицинские, социальные и семейные меры;</li>\n<li>Целостность системы воспитания, последовательно формирующей правильные нормы и модели поведения у подрастающего поколения;</li>\n<li>Активное привлечение родительского участия, развивающее ответственность и компетенции родителей в области профилактики;</li>\n<li>Создание благоприятной социальной среды, обеспечивающей полноценное развитие детей вне стен образовательных учреждений;</li>\n<li>Дифференцированный подход к каждому ребёнку, учитывая его личностные характеристики, условия обитания и жизненную ситуацию.</li>\n</ul>\n<p><strong>Практические рекомендации</strong></p>\n<p>Для улучшения качества профилактической работы рекомендуется предпринять следующие шаги:</p>\n<ul>\n<li>Включить профилактику в повседневную учебную деятельность посредством регулярных занятий, конкурсов и творческих мероприятий;</li>\n<li>Использовать современные информационно-коммуникационные технологии и интерактивные методы для привлечения внимания подростков к проблемам здорового образа жизни;</li>\n<li>Создавать механизмы систематического мониторинга эффективности проводимых мероприятий;</li>\n<li>Повышать грамотность родителей относительно симптоматики и начальных проявлений злоупотребления ПАВ;</li>\n<li>Организовывать семейные мероприятия, коллективные дискуссии и культурные походы, укрепляющие связь поколений;</li>\n<li>Осваивать методики эффективного общения с подростками, учась выстраивать доверительные взаимоотношения и создавать комфортную атмосферу доверия.</li>\n</ul>\n<p>Таким образом, успешно предотвращение злоупотребления психоактивными веществами возможно лишь при условии комплексной, многоуровневой и индивидуально ориентированной работы, активно поддерживаемой всеми участниками педагогического процесса и обществом в целом.</p>','2026/02/pub_20260227_082231_8ecc6e89.docx','статья ПАВ.docx',18838,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',2,'profilaktika-zloupotrebleniya-pav-sredi-detey-i-podrostkov',NULL,NULL,34,0,'published',NULL,'auto_approved','2026-02-27 08:22:31',0.90,'ready','2026-02-27 08:22:31','2026-02-27 05:22:31','2026-03-05 00:30:30'),(20,48,'Роль семьи в формировании читательской компетенции дошкольника','В статье рассматривается роль семьи в приобщении детей дошкольного возраста к чтению. Автор анализирует влияние семейного чтения на развитие ребёнка и даёт практические рекомендации для родителей по выбору литературы, организации читательского пространства и обсуждению прочитанного.','<p><strong>Название:</strong> <strong>Роль семьи в формировании читательской компетенции дошкольника: от традиции к привычке</strong></p>\n<p><strong>Аннотация.</strong>В статье рассматривается фундаментальная роль семьи в процессе приобщения детей дошкольного возраста к чтению. Автор анализирует влияние семейного чтения на речевое, эмоциональное и когнитивное развитие ребенка. Особое внимание уделяется практическим аспектам взаимодействия родителей с детской книгой: критериям выбора литературы, методам обсуждения прочитанного и организации читательского пространства дома. Материал содержит конкретные рекомендации для родителей, направленные на формирование устойчивого интереса к художественной литературе и бережного отношения к книге.<br></p>\n<p><strong>Введение</strong><strong>:</strong> Художественная литература входит в жизнь ребенка с первых лет и сопровождает его на протяжении всего детства. Литературное произведение предстает перед маленьким читателем в единстве содержания и художественной формы, постепенно формируя его эстетический вкус и избирательное отношение к миру словесности. Все последующее знакомство с огромным литературным наследием будет опираться на тот фундамент, который закладывается в дошкольном детстве. Ребенок проходит длительный путь от наивного участия в изображаемых событиях до более сложных форм эстетического восприятия. Произведения художественной литературы являются важнейшими источниками развития выразительности детской речи, они открывают и объясняют ребенку жизнь общества и природы, мир человеческих чувств и взаимоотношений.</p>\n<p>Основной педагогической задачей на этапе дошкольного детства является привитие детям любви к художественному слову и уважения к книге. Именно родители во многом определяют круг читательских интересов дошкольников, поэтому так важно расширять представления самих родителей о детской литературе и методах взаимодействия с ней.</p>\n<p><strong>Основная часть.</strong></p>\n<p><strong>Создание развивающей книжной среды в семье</strong></p>\n<p>Приобщение ребенка к чтению начинается не с обучения буквам, а с создания особой атмосферы, где книга занимает почетное место. Народная мудрость гласит: «С книгой поведешься — ума наберешься», «Хорошая книга — лучший друг». Чтобы эти пословицы стали реальностью для современного ребенка, родителям необходимо учитывать несколько ключевых аспектов.</p>\n<p><strong>1. Возрастные и физические параметры книги</strong></p>\n<p>Выбирая литературу для малыша, следует помнить о критериях легкости и прочности. Хорошая книга для маленьких имеет ряд особенностей:</p>\n<ul>\n<li><strong>Вес и прочность:</strong> издание должно быть легким, чтобы ребенок мог самостоятельно достать его с полки. Оптимальным материалом является плотный картон.</li>\n<li><strong>Полиграфия:</strong> в книге должны быть крупные, яркие картинки с минимумом отвлекающих деталей. Печатный текст — только крупный, фразы — четкие и лаконичные. Если страница занята яркой иллюстрацией, текст обязательно располагается на светлом фоне.</li>\n<li><strong>Безопасность:</strong> необходимо обращать внимание на наличие гигиенического сертификата, так как маленькие дети часто исследуют мир, пробуя предметы на вкус.</li>\n</ul>\n<p><strong>2. Принцип «Всему свое время»</strong></p>\n<p>Развитие читательского интереса должно идти параллельно с развитием ребенка:</p>\n<ul>\n<li><strong>Ранний возраст (до 2 лет).</strong> Самым маленьким нужны книги для рассматривания. Картинка должна занимать не менее 80% страницы, а текст состоять из 2-3 слов. Чтение в этом возрасте — это всегда совместное действие взрослого и ребенка, сопровождаемое интонацией и жестами.</li>\n<li><strong>Младший дошкольный возраст (2–3 года).</strong> В это время появляется интерес к буквам, и можно приобретать азбуку. Важно помнить: узнавание букв и чтение — процессы разные; сейчас читает взрослый, а ребенок активно слушает.</li>\n<li><strong>Средний дошкольный возраст (3–4 года).</strong> «Возраст почемучек» — оптимальное время для знакомства с детскими иллюстрированными энциклопедиями. Количество незнакомых слов не должно превышать 10–15%, иначе книга покажется скучной.</li>\n<li><strong>Старший дошкольный возраст (5–7 лет).</strong> Круг чтения расширяется. Задача родителей — подбирать разнообразные книги и ходить в книжный магазин вместе с ребенком, предоставляя ему право выбора.</li>\n</ul>\n<p><strong>Методика организации семейного чтения</strong></p>\n<p>Процесс чтения не должен быть стихийным. Педагогическая компетентность родителей проявляется в умении выстроить систему.</p>\n<p><strong>Ритуалы и традиции.</strong>Чтение должно стать неотъемлемой частью распорядка дня. Наполняйте день ребенка малыми фольклорными формами: потешками, прибаутками. Обязательным ритуалом должно стать чтение перед сном. Дети неохотно ложатся спать и воспринимают вечернее чтение как возможность отдалить отход ко сну, что со временем превращает это занятие в устойчивую позитивную традицию.<br></p>\n<p><strong>Систематичность.</strong>Читать необходимо каждый день. Даже при высокой занятости взрослого, следует выделять время хотя бы на несколько страниц. Если ребенок просит почитать, никогда не стоит ему отказывать.<br></p>\n<p><strong>Обсуждение прочитанного.</strong>Диалог о книге не менее важен, чем сам процесс чтения. Рекомендуется придерживаться следующего алгоритма беседы:<br></p>\n<ul>\n<li>Выяснить значение незнакомых слов до или во время чтения.</li>\n<li>Спросить, понравилось ли произведение и чем именно.</li>\n<li>Попросить ребенка рассказать о главном герое или событии.</li>\n<li>Обратить внимание на описание природы, запомнившиеся выражения.</li>\n<li>Обсудить, чему научила книга, какой вывод можно сделать.</li>\n<li>Предложить нарисовать понравившийся эпизод или выучить отрывок.</li>\n</ul>\n<p><strong>Воспитание бережного отношения к книге</strong></p>\n<p>Параллельно с развитием интереса к содержанию, необходимо формировать культуру обращения с книгой. Родителям рекомендуется транслировать ребенку следующие правила:</p>\n<ul>\n<li>Не делать в книге пометок и рисунков.</li>\n<li>Не читать во время еды.</li>\n<li>Не загибать листы, а использовать закладку.</li>\n<li>Класть книгу только на чистый стол.</li>\n<li>Хранить книги в одном специально отведенном месте.</li>\n<li>Своевременно оказывать «скорую помощь» поврежденным книгам.</li>\n</ul>\n<p><strong>Интерактивные формы работы с текстом</strong></p>\n<p>Для поддержания интереса к чтению можно использовать игровые приемы:</p>\n<ul>\n<li><strong>«Прятки с книжкой».</strong> Взрослый прячет новую книгу в комнате, а ребенок ищет ее. Наградой за находку становится чтение.</li>\n<li><strong>«Угадай-ка».</strong> Предложите ребенку по иллюстрациям угадать содержание еще незнакомой книги.</li>\n<li><strong>«Новое окончание сказки».</strong> После прочтения знакомой сказки (например, «Колобок») предложите ребенку придумать другой финал.</li>\n<li><strong>«Прыг — и в другой сказке».</strong> Совместное сочинение новой истории про известного героя.</li>\n</ul>\n<p><strong>Заключение</strong></p>\n<p>Если у родителей есть желание, начинать читать ребенку можно с самого рождения. Новорожденный не понимает смысла, но прекрасно различает интонации и считывает эмоциональное состояние взрослого. Чтение с удовольствием, а не по обязанности, формирует у младенца положительное отношение к этому занятию на глубинном, эмоциональном уровне.</p>\n<p>Даже когда ребенок научится читать самостоятельно, не следует прекращать практику совместного чтения. Взрослый читает более эмоционально, создавая живые образы, объясняет непонятные моменты и, что самое важное, такое чтение сплачивает семью, делая книгу не просто источником информации, а центром духовного общения.</p>','2026/02/pub_20260227_132128_b6460868.docx','Статья. Роль семьи в формировании читательской компетенции дошкольника от традиции к привычке.docx',20744,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',2,'rol-semi-v-formirovanii-chitatelskoy-kompetentsii-doshkolnika',NULL,NULL,65,0,'published',NULL,'auto_approved','2026-02-27 13:21:29',0.00,'pending','2026-02-27 13:21:28','2026-02-27 10:21:28','2026-03-04 21:07:23'),(21,685,'Жизнь без интернета','Публикация представляет собой сценарий беседы, направленной на развитие умений учащихся работать с дополнительной литературой и информацией без помощи интернета, стимулирование познавательного интереса к предметам познания мира и воспитание чувства ответственности за окружающий мир. В ходе беседы обсуждаются вопросы жизни без интернета, его влияния на человека и общество, а также проводятся конкурсы и игры на знание природы и животных.','<p><strong>«Представим жизнь</strong><strong> без интернета»</strong></p>\n<p><strong>Задачи:</strong></p>\n<p>1. развить умения учащихся работать с дополнительной литературой, информацией без помощи интернета;</p>\n<p>2. стимулировать познавательный интерес к таким  предметам, как  познание мира;</p>\n<p>3. воспитывать чувство ответственности окружающий мир.  </p>\n<p><strong>Ход беседы</strong><strong>:</strong></p>\n<p><strong>Вступительное слово воспитателя</strong><strong>. </strong></p>\n<p>Всем добрый день! Я рада приветствовать вас на нашей беседе.</p>\n<p>В мире происходит очень много интересного. Чтобы что-то узнать мы сразу пользуемся   интернетом. Да, на сегодняшний день интернет- это самый колоссальный источник информации, который знало человечество.  Его возможности, такие, как оперативность, быстрота и доступность связи между пользователями на дальних и близких расстояниях, позволяют использовать интернет не только как инструмент для познания, но и как инструмент для общения.</p>\n<p>Невозможно представить себе жизнь без интернета, который вошёл во все сферы деятельности, быта и культурной жизни человека. Для многих людей он становится большой информационной виртуальной книгой, без которой они не смогли бы прожить. Интернет настолько многогранный, что каждый находит в нём что-то нужное и ненужное, интересное и бесполезное. Так что в интернете есть свои + и свои -.</p>\n<p>А вы знаете, что 30 января в мире отмечается Международный День БЕЗ Интернета(International Internet-Free Day).</p>\n<p>Главная цель данного праздника – полностью отвлечь людей от компьютеров и глобальной сети хотя бы на один день, чтобы прожить этот день исключительно в «реальном» мире, общаться с другими людьми исключительно «вживую» или посвятить его своему любимому хобби (конечно же, не связанному с интернетом).</p>\n<p>Смогли бы вы хоть один день обойтись без него? (ответы детей)</p>\n<p>Но раньше интернета не было. Как же жили люди без него? Как общались?</p>\n<p>Вам было задано домашнее задание: написать сочинения со слов взрослых о том, как они жили раньше без сотовых телефонов, компьютеров. Сей час мы их послушаем. ( дети зачитывают несколько работ). </p>\n<p>Что вы можете сказать об услышанном? Нужен ли нам сейчас интернет? Приносит он вред или пользу? (дети отвечают). Сети интернета полностью оплели наш мир. В свободное время мы пропадаем на разных сайтах, не замечая того, что находится вокруг нас. А вокруг, такой интересный мир, столько всего замечательного.  Я предлагаю  окунуться вам в мир природы и поучаствовать в игре <strong>«Счастливый случай».</strong> </p>\n<p>(дети делятся на команды) </p>\n<p><strong>1конкурс.</strong> Приветствие и представление команд (название, девиз).</p>\n<p><strong>2 конкурс</strong><strong>.</strong> Разминка. Командам предлагается ответить на несколько вопросов по очереди.</p>\n<p><strong>Вопросы для 1 команды:</strong></p>\n<p>Трава от 99 болезней (зверобой)</p>\n<p>На следу, каких хищных зверей нет когтей? (кошки, рыси)</p>\n<p>Слепыми или зрячими родятся зайцы?  (зрячими)</p>\n<p>Кто собирает яблоки спиной? (ёж)</p>\n<p>Пингвины- птица или нет? (птица)</p>\n<p>Какая ягода бывает чёрной, красной, белой?  (смородина)</p>\n<p>У какого дерева ствол белый?  (берёзы)</p>\n<p>Какая птица выше всех летает?  (орёл)</p>\n<p>Какая птица самая маленькая? (королёк)</p>\n<p>Кто спит головой вниз? (летучая мышь)</p>\n<p>Когда чаще всего бывает первая гроза?  (в мае)</p>\n<p>Что случается с пчелой после того, как она ужалит?  (умирает)</p>\n<p><strong>Вопросы 2 команде:</strong></p>\n<p>Какая птица подбрасывает яйца в  чужие гнёзда? (кукушка)</p>\n<p>Название, какого растения говорит, где оно растёт? (подорожник)</p>\n<p>Кто бежит, выставляя вперёд задние ноги?  (заяц)</p>\n<p>Кровожадный хищник наших лесов?  (волк)</p>\n<p>Животное наших лесов похожее на кошку  (рысь)</p>\n<p>Когда ёж не колется?  (когда он родился)</p>\n<p>Зимуют ли птицы в скворечниках?  (нет, там холодно)</p>\n<p>Чьи листья опадают осенью зелёными?  (ольхи)</p>\n<p>Какая птица достаёт себе пищу подо льдом? (оляпка)</p>\n<p> Где у кузнечика ухо?  (на ноге)</p>\n<p>Что теряет лось каждую зиму? (рога)</p>\n<p>Сколько ног у паука?  (8)</p>\n<p><strong>3конкурс.</strong> «В мире животных». Ребятам было дано домашнее задание: приготовить репортаж о заповедниках без помощи интернета с демонстрацией источника.</p>\n<p>Команды представляют свои работы.</p>\n<p><strong>4конкурс.</strong> «Угадай мелодию».</p>\n<p>Участникам предлагается угадать песни о животных (включаются минусовки). Песни могут быть любые, в которых есть названия животных, например: «В траве сидел кузнечик», «Чёрный кот», «Мы едем, едем, едем…», «Где-то на белом свете», «Пропала собака», «Люси» , «Собака бывает кусачей», «Лесной олень», «У дороги чибис», «Далеко, далеко на лугу пасутся ко...», «Розовый слон», «Два веселых гуся», «Зайка моя», «У пони длинная чёлка», «Облака - белогривые лошадки», «Песенка львёнка и черепахи», «Вы слыхали, как поют дрозды?», «Три белых коня», «Ой, мороз, мороз».</p>\n<p><strong>5 конкурс.</strong> «Зов джунглей»</p>\n<p>Со всех дворов зовем гостей. Чем больше, тем и веселей</p>\n<p>Что у нас тут приключилось? Вы узнаете сейчас:</p>\n<p>Вот позвали в джунгли нас крокодилы, обезьяны!</p>\n<p>Других зверей немало тут, в общем, в джунгли нас зовут!</p>\n<p>В этом туре можно просто поиграть в различные игры.</p>\n<p>«Звериная перекличка» </p>\n<p>Команды по очереди называют животных, обитающих в нашей стране, выигрывает команда, закончившая называть животных последней.<em> </em></p>\n<p><strong>6</strong><strong>конкурс.</strong><strong> </strong>“Заморочки из бочки”</p>\n<p>Почему у уток на лапках перепонки?</p>\n<p><u>Ответ</u>: эти перепонки нужны уткам, чтобы передвигаться в воде; утки плывут, вращая лапками, как ластами. Перепончатой лапкой можно загребать гораздо больше воды.</p>\n<p>Как головастики превращаются в лягушек?</p>\n<p><u>Ответ</u>: у них вырастают передние, затем задние лапки и отпадают хвостики.</p>\n<p>Почему у жирафов шея длинная?</p>\n<p><u>Ответ</u>: жирафы, благодаря длинной шее могут поедать листья, до которых другим животным не дотянуться.</p>\n<p>Почему погибнет лес, в котором вырубят все старые дуплистые деревья?</p>\n<p><u>Ответ</u>: в дуплах деревьев живут птицы. Вырубили лес – улетели птицы – появилось много гусениц и насекомых – лес погиб.</p>\n<p>У птенцов рот ярко красный или оранжевый. Почему?<br><u>Ответ</u>: красный цвет – сигнал тревоги, опасности. Привлеченные красным цветом птицы-родители, суют корм в открытый клюв.</p>\n<p><strong>7конкурс.</strong><em> </em>“Темная лошадка”</p>\n<p>1. а) Многолетнее травянистое растение, цветы белые, ягодка как шарик. Запах и вкус необычный. Растет ягодка на болоте, во мхах, не боится мороза. Ягоды собирают, варят компоты и варенье. А еще используют ягоды при заболевании сердца и снятия болей в груди, при простуде и как кровоостанавливающее средство. <em>(Морошка)</em></p>\n<p>б) Можно ли охотиться на зверей и птиц весной? <em>(Нет)</em></p>\n<p>2. а) Этот цветок неотделим от русской природы, с ранней весны и до сентября встречаем его на дорогах, в парках и садах, в лесу и на лугах. Листья узорчатые и продолговатые, стебелек длинный, как трубочка. Известен целебными свойствами. <em>(Одуванчик)</em></p>\n<p>б) Как можно уберечь животных и птиц от истребления?</p>\n<p>3. а) У меня головка в черной шапочке, спинка, крылья и хвост темные, а грудка ярко-желтая, будто в желтый жилет нарядилась. Летом я питаюсь жучками, червячками, а зимой, в бескормицу, ем все: и разные зернышки, и крошки хлеба, и вареные овощи. Но особенно я люблю несоленое сало. Догадались, кто я? <em>(Синичка)</em></p>\n<p>б) Какой вред причиняют кислотные дожди? <em>(Загрязняют водоемы, почвы, губят растения)</em></p>\n<p>4. а) У меня желтые надкрылья с черными полосами. От врагов я защищаюсь едкой жидкостью с противным, раздражающим запахом. Я хорошо летаю и в воде не тону. Люблю лакомиться зеленью томатов, картофеля, баклажанов. А детки мои – личинки красного цвета, очень прожорливы. Кто я? <em>(Колорадский жук)</em></p>\n<p>б) Как можно остановить размывание почвы? <em>(С помощью посадки деревьев)</em></p>\n<p>5. а) Мы живем большими семьями. В каждой семье есть самая крупная самка – матка. Есть у нас и лентяи – трутни. Но больше всего в нашей семье – рабочих. У человека мы живем в специальных домиках. Мы очень любим лакомиться пыльцой и собирать нектар с цветов. Кто мы? <em>(Пчелы)</em></p>\n<p>б) Что из перечисленного служит источником загрязнения: <em>самолеты</em>, велосипеды, <em>автомобили</em>, парусные лодки?</p>\n<p>В заключении детям предлагается поиграть в игру «Воробьи и вороны».</p>\n<p> Одна команда будет воробьями, а другая воронами. Ведущий говорит: «Воробьи», тогда воробьи бегут и ловят ворон, если ведущий говорит : «Вороны», то наоборот вороны ловят воробьёв.</p>\n<p><strong>Подведение итогов, награждение победителя.</strong></p>\n<p>Вот видите, как хорошо мы провели время. И каждый из вас может обходиться без помощи интернета. Вам будет дано задание, которое вы предоставите 30 января. Это ваше сочинение о том, как вы проведете несколько дней без сотовых телефонов и компьютеров. А, прослушав их, мы выберем лучшее.</p>\n<p><strong>ГБ ОУ РМ «</strong><strong>Инсарская</strong><strong> общеобразовательная школа-интернат для детей сирот и детей, оставшихся без попечения родителей, с ограниченными возможностями здоровья»</strong></p>\n<p><strong>Открытая беседа</strong></p>\n<p>«Представим жизнь без интернета»</p>\n<p><strong>                               Подготовила: воспитатель Лобанова О.П. </strong></p>\n<p><strong>Инсар 2023 г</strong>.</p>','2026/02/pub_20260227_134240_90cb290a.docx','predstavim_zhizn_bez_interneta.docx',24149,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',5,'zhizn-bez-interneta',NULL,NULL,37,0,'published',NULL,'auto_approved','2026-02-27 13:42:41',0.95,'pending','2026-02-27 13:42:41','2026-02-27 10:42:40','2026-03-04 19:01:38'),(22,1452,'Конспект занятия. Чтение сказки \"Три медведя\"','Методическая разработка занятия по чтению сказки Л. Н. Толстого \'Три медведя\' в дошкольной группе. Включает организационный момент, знакомство со сказкой, динамическую паузу, вопросы по содержанию сказки и подвижную игру.','<p>Тема: Чтение сказки Л. Н. Толстого &quot;Три медведя&quot;.<br>\nПрограммные задачи: Познакомить со сказкой «Три медведя», приучая их внимательно слушать<br>\nотносительно большие по объему художественные произведения.<br>\nЗадачи:<br>\nвоспитательные - продолжать формировать умение слушать взрослого; не перебивая, дослушивать его<br>\nдо конца; формировать положительные качества, умение сопереживать;<br>\nобучающие - продолжать расширять словарный запас детей; способствовать употреблению усвоенных<br>\nслов в самостоятельной речи;<br>\nразвивающие - развивать умение вслушиваться в речь взрослого; развивать внимание, воображение и<br>\nмышление.<br>\nХод занятия:<br>\n1. Организационный момент.<br>\nВоспитатель поощряет детей навести порядок в группе и обращает внимание на стук в двери. (Тук, тук,<br>\nтук!) «Кто там?»<br>\nЗаходит медвежонок (БИ-БА-БО): Здравствуйте, ребята! Я медвежонок Мишутка. Пришел к вам в<br>\nгости. (Дети здороваются). Я принес вам подарок.<br>\nВоспитатель: Смотрите, Медвежонок принес нам книжку (воспитатель показывает детям книгу).<br>\n         Кто догадался, как называется сказка? (ответы детей, на обложке нарисованы три медведя).<br>\n         Медвежонок просит почитать сказку. А вы хотите послушать сказку « Три медведя?» (Да).<br>\nТогда садитесь и слушайте.<br>\n2. Знакомство со сказкой. Чтение сказки с показом иллюстраций.<br>\n3 Динамическая пауза:<br>\nВоспитатель: Вам понравилась сказка? (Ответы детей).<br>\n         А Медвежонку очень понравилась сказка. Смотрите, он танцует.        Давайте потанцуем<br>\nвместе с ним.<br>\n (имитируют движения медведя, выполняют движения по тексту):<br>\n                            Вышел мишка из берлоги, отлежал бедняга ноги:<br>\n                                 Приседает, топает и в ладоши хлопает!<br>\n                            Звери все перепугались, от медведя разбежались.<br>\n                             Кто летит, кто бежит, кто под елочкой дрожит.<br>\n                                 Веткой ива машет, косолапый пляшет!<br>\n4. Подумай и ответь.<br>\nВоспитатель побуждает детей ответить на вопросы по содержанию сказки:<br>\nЧто случилось с Машей в лесу?<br>\nА как она звала подружек? (АУ-АУ) - артикуляционная гимнастика.<br>\nКто жил в домике? Как звали медведей?<br>\nЧья каша понравилась Маше? Каша была вкусная - покажите, как понравилась каша Маше? (М-М-М).<br>\nЧей стульчик понравился Маше?<br>\nЧто Маша сказала, когда упала со стула и ударилась? (ОЙ-ОЙ).<br>\nПочему стульчик сломался?<br>\nЧья кроватка показалась Машеньке самой удобной?<br>\nПокажите, как рассердились медведи, когда вернулись домой и увидели беспорядок? Что сказал<br>\nкаждый медведь, каким голосом?<br>\nЧто закричал медвежонок, когда увидел Машу в своей кроватке, каким голосом?<br>\nПокажите, как девочка испугалась медведей?<br>\nВоспитатель: Девочка Маша поступила не правильно. Нельзя трогать чужие вещи. Медвежонок<br>\nМишутка очень расстроился, что Маша съела его кашу и сломала его стульчик. Маме - медведице<br>\nНастасье Петровне пришлось долго укачивать Мишутку в кроватке и петь ему колыбельную: &quot;А-А-А,<br>\nА-А-А&quot;.<br>\nДети подпевают воспитателю - артикуляционная гимнастика.<br>\n5. Подвижная игра.<br>\nВоспитатель: Мишутка поспал и зовет вас играть, он вас будет догонять, а вы будете убегать от<br>\nМишутки на коврик (игра продолжается 2-3 раза):<br>\n                              У медведя во бору грибы ягоды беру,<br>\n                               А медведь не спит и на нас глядит.<br>\n6. Подведение итогов.<br>\nВоспитатель положительно оценивает работу детей, медвежонок хвалит каждого малыша (гладит по<br>\nголовке).</p>','2026/02/pub_20260228_095816_ba76a714.pdf','Конспект занятия Чтение сказки Три медведя.pdf',547724,'application/pdf',1,'konspekt-zanyatiya-chtenie-skazki-tri-medvedya',NULL,NULL,55,0,'published',NULL,'auto_approved','2026-02-28 09:58:17',0.95,'ready','2026-02-28 09:58:17','2026-02-28 06:58:16','2026-03-05 03:38:27'),(23,1890,'Сэрии хаарыйбатах дьоно диэн суох','Публикация посвящена исследованию жизни и подвигов участников Великой Отечественной войны, связанных с местностью Чүүйэ. Описываются судьбы конкретных людей, их вклад в историю и значение их действий для местного сообщества. Особое внимание уделяется описанию конкретных событий и личностей, связанных с войной.','<p>Дакылаат тиэмэтэ:</p>\n<p><strong>Сэрии х</strong><strong>а</strong><strong>арыйбатах дьоно диэн суох</strong></p>\n<p><strong>В.В. Скрябин аатынан </strong></p>\n<p><strong>Чүүйэ орто оскуолатын</strong></p>\n<p><strong>7 кылааһын үөрэнээччитэ</strong></p>\n<p><strong>Федорова Юлиана үлэтэ</strong></p>\n<p><strong>Салайаччы: Федорова Екатерина Николаевна</strong></p>\n<p><strong>В.В. Скрябин аатынан </strong></p>\n<p><strong>Чүүйэ орто оскуолатын педагог-бибилитиэкэрэ.</strong></p>\n<p><strong>Иһинээҕитэ</strong></p>\n<p>Киириитэ..........................................................................................................3</p>\n<ul>\n<li>Баһа. Сэрии биһиги аймахха содула...........................................3</li>\n<li>Баһа. Климентовтар төрүттэрэ.....................................................6</li>\n</ul>\n<p>2.1. Төрүттэрэ Филипп Климентов – “Суруксут Силип”..........6</p>\n<p>                   2.2. Иитиллибитинэн Климентовтар ..........................................6</p>\n<p>                   2.3. Кэскил дьиэ-кэргэҥҥэ түстэнэр............................................7</p>\n<p>Түмүгэ..............................................................................................................11</p>\n<p>Туһаныллыбыт литература............................................................................12</p>\n<p><strong>Киириитэ</strong></p>\n<p><strong>Үлэ тоҕоостооҕо:</strong><strong>  </strong></p>\n<p>Улуу Кыайыы суолтата биһиги өйбүтүттэн-санаабытыттан хаһан да сүтүө суоҕа. </p>\n<p>     Сэрии иэдээнэ тугунан да кэмнэммэт, мээрэйдэммэт. Кыайыы туһугар аҕа көлүөнэлэр, олохторун толук уурбуттарын, күүһү таһынан үлэлээбиттэрин, тоҥмуттарын – аччыктаабыттарын кэнники көлүөнэлэр билиэхтээхпит, “харах уулаах бырааһынньык” диэн тоҕо ааттыылларын өрүү өйдүү-саныы сылдьыахтаахпыт. Хас биирдии киһи бу орто туруу дойдуга олох олороору, кэнниттэн кэнчээри ыччатын хааллараары, дьол диэн тугун билээри кэлэр. Бу сэриигэ олох олорбокко, аҕа ууһун салҕабакка төннүбүт төһөлөөх киһи баара буолуой? Сэрии диэн бу олох иэдээнэ, алдьархайа! Сэрии алдьархайа аны хаһан да хатыламматын, эйэлээх олоҕу уһансыбыт үтүө дьоммут ааттара үйэлэр тухары умнуллубатын!</p>\n<p><strong>Чинчийии сыала:</strong> Хас биирдии оҕо, дьиэ кэргэн, аймах бэйэтин төрдүн-ууһун билиэхтээх, үөрэтиэхтээх.</p>\n<p><strong>Соруктара:</strong></p>\n<ul>\n<li>Төрдүн – ууһун билбэт киһи силиһэ быстыбыт мас курдук кэхтэн – эстэн барыаҕа;</li>\n<li>Климентовтар төрүттэрэ;</li>\n<li>Аҕа дойду сэриитигэр өстөөхтөрү утары охсуспут ини – бии Климентовтар.</li>\n<li><strong>баһа. Сэрии биһиги аймахха содула</strong></li>\n</ul>\n<p>      Күн-дьыл аастаҕын аайы Улуу Кыайыы суолтатын ордук дириҥник өйдүүгүн. Кыайыы туһугар сэриилэспиттэр, тыылга үлэлээбиттэр, сэрии сылларыгар  аас-туор олохтоммут оҕолор – бу барыта биһиги дьоммут , бары биир ситимнээхпит. Сэрии хаарыйбатах дьоно диэн суох. Дьон төрдүн-ууһун диэки хайыста, кимтэн кииннээҕин ырытар буолла, хантан хааннааҕын хасыһан билэ сатыыр идэлэннэ. Бу үчүгэй. Үгүспүт кырдьаҕастарбыт барбыттарын кэннэ биирдэ өйдөннүбүт, ыйыталаһыахпыт иһин аттыбытыгар билээччилэрбит номнуо суох буолбуттар. Оҕо сылдьан кэпсииллэрин иҥэн-тоҥон истибэтэх, суолталаабатах эбиппит. Биир бэйэм Сээркээн сэһэнньит эһэлээх этим, Дьөгүөр Борокуоппайабыс Доҕордуурап диэн, сүрдээх үлэһит, тоҕус уонун лаппа ааһан баран бу орто дойдуттан оҕолорун, сиэттэрин ортолоругар сымнаҕастык барбыта. Кини биир эрэ нэдиэлэ сыппыта, ол сытыар диэри хотоҥҥо балбаах соһон, мууһун-маһын киллэрэ сылдьыбыта, өлүөн биир сыл иннинээҕи сайыҥҥа дылы күөлгэ тыынан киирэн туулаан тахсара. Эһэм үлэ фронугар сылдьыбыт, бэрт элбэхтик таһаҕас таһыытыгар Өлүөхүмэнэн, Алданынан айаннаабыт холкуос туруу үлэһитэ этэ. Кини Маачаҕа үлэ фронугар сылдьыбытын кэпсиирэ, онно үп-үрүҥ харахтаах, иккилии миэтэрэ үрдүктээх пиин омуктар бааллара, ол эрэйдээхтэр чуолҕан түннүгүнэн нуорма килиэптэрин ылан, муустаах уулаах буочукаттан уу иһэн баран сарсыарда мас кэрдэ үүрүллэн бараллара, киэһэ хараҥа буолбутун кэннэ үүрүллэн  кэлэллэрэ, эмиэ чуолҕаннарыттан килиэп ылан, муустаах  ууну иһэн, утуйа бараллара диэн кэпсиирэ. Ол дьон өлөн бөҕөлөр үһү, улахан да, кыра да буол, нуорма килиэбиҥ тэҥ буоллаҕа. Эһэлээх-эбэм Үөһэ-Бүлүү Хомустааҕар хоргуйан, ыксаан, Тамалакааҥҥа көһөн кэлбиттэр. Манна олордохторуна араас быстарбыттар, ыарыһахтар хонон ааһалларын кэпсииллэрэ. Дьон хоргуйуута сүрдээх үһү, оттон Тамалакааҥҥа  дьон быстарбатах, оччотооҕу холкуос салайааччыларын үтүөлэринэн. Оҕо эрдэхпитинэ, Үөһээ-Бүлүүгэ олохсуйбуппут кэннэ, биһиэхэ Хомустаах киһитэ Лебедкин сылдьан ааһара. Дьонум кинини наһаа аһынар этилэр, чэйдэтэ сатыыллара, киһилэрэ тымныы ууну иһэн баран тахсан барара. Наар итирик буолара. Кинини дьон «Танкист, вперед!», «майор» диэн ааттыыллара. Таанкаҕа умайбыт дииллэрэ. Майор званиелаах, уордьаннаах үһү. Аны санаатахха, сэриигэ отуора хамсаан, хаана алдьаммыт, эйэлээх олоххо сатаан миэстэтин булбатах киһи эбит, өр барбатаҕа, өлбүт этэ. Дьон да сыһыана мөлтөх быһыылааҕа, кини итирэн сэриигэ сылдьар курдук тыллаһарын күлүү-элэк гынар курдук кэпсииллэрэ. Арай мин дьонум киһилии сыһыаннаһаллар быһыылааҕа, оттон биһиги, оҕолор, эмиэ итирик киһи киирдэ диэн абааһы көрөр этибит да, өр буолбат этэ, тахсан барара. Таайым Ньукулай Дьөгүөрэбис Доҕордуурап Дьоппуон сэриитигэр сылдьан кэлбит этэ, оччолорго кинилэри ким да сэриигэ сылдьыбыттар ахсааннарыгар киллэрбэт этэ. Сэриигэ сылдьан аччыктаабытын, утаппытын, утаппытын туһунан кэпсиир буолара.</p>\n<p>     Бу сааһыран баран билбитим, аҕам бииргэ төрөөбүттэрэ түөрт ини-бии Буораахаптар Тамалакаантан сэриигэ баран өлбүттэр эбит. Кинилэр сырдык ааттарын кэриэстээммин ааттыыбын: </p>\n<ul>\n<li>Василий Михайлович Буораахап, 1912 сыллааҕы төрүөх, 1941 сыллаахха фроҥҥа барбыт, 1943 сыл кулун тутар 19 күнүгэр кыргыһыы хонуутугар охтубут, Тула куорат таһыгар Угадскай СЭТ-1381 диэн сиргэ көмүллүбүт. </li>\n<li>Трофим Михайлович Буораахап, 1902 сыллаах төрүөх, 1942 сыллаахха ыҥырыллыбыт, 1942 сыл алтынньытыгар өлбүт, Сталинград анныгар Кузьмичи дэриэбинэҕэ көмүллүбүт.</li>\n<li>Абрам Петрович Антонов (ыалга иитиллибитинэн), 1915с.т. 1941 сыллаахха ыҥырыллыбыт, 1947сыллаахха өлбүт, ханна көмүллүбүтэ биллибэт. </li>\n<li>Игнатий Михайлович Прокопьев, Буораах диэн аатын сөбүлээбэккэ, бэйэтэ уларыттарбыт, 1923 сыллаах төрүөх. 1941 сыллаахха ыҥырыллыбыт, бааһырыытыттан 1946 сыллаахха өлбүт, Хабаровскай куоракка көмүллүбүт.</li>\n</ul>\n<p>     Эһэбин кытта бииргэ төрөөбүт балта Аана Үөһээ-Бүлүү Далырыгар олорбут, Никиитэ диэн оҕонньордоох, күҥҥэ көрбүт соҕотох оҕолоро Михаил Никитич Дондуров, 1921 сыллааҕы төрүөх, 1941 сыллаахха сэриигэ тылланан барбыт курдук, связист үһү диэн буолара. 1942 сыллаахха сураҕа суох сүппүт диэн биллэриигэ кэлбит. Ийэтэ Аана хара өлүөр диэри, сэттэ уонуссыллар буолуохтарыгар дылы, оҕотун күүппүтүн туһунан ССРС норуодунай учуутала Михаил Андреевич Алексеев суруйууларыгар баар. Астаабыт аһыттан ууран, суол төрдүн манаан олороохтообута үһү. Кэлин биллибитинэн, кини Калининградскай уобалас Ржевскэй оройуонун Собакино диэн дэриэбинэтигэр көмүллэ сытар эбит. Бу туһаайыынан эмиэ суолталаах кырыктаах кыргыһыылар буолбуттара биллэр.</p>\n<p>     Дьылҕа Хаан ыйааҕынан Магадан куоракка пединститутка үөрэнэ сылдьан Мэҥэ-Хаҥалас уолугар Климентов Терентий Терентьевичкэ кэргэн тахсаммын, ыал буолан, түөрт оҕону төрөтөн, улаатыннардыбыт, элбэх сиэннэннибит. Холбоһон баран билбитим, Климентовтартан эмиэ түөрт киһи сэриигэ баран, кыргыһыы  хонуутугар охтубуттар эбит. Хотунум Татьяна Михайловна Климентова (Григорьева) кэпсээниттэн элбэҕи билэн, бу аймах сэриигэ наһаа хаарыйтарбытын билбитим. Онон Кыайыы 60 сылыгар ини-бии Климентовтар  тустарынан «Биһиги аймахха сэрии содула» диэн дакылаат оҥорон, сэттис кылааска үөрэнэр сиэним Сережа Бурцев “Колесо истории” диэн  конференцияҕа кыттыыны ылбыта. Онтон бэһис кылааска үөрэнэр сиэним  Аня Охлопкова эбэтин аймахтарын туһунан «Сэрии огдообото  уонна сэрии тулаайахтара» диэн дакылаатынан кыттыбыта. Сити сыл Тараҕай нэһилиэгин Табаҕа орто оскуолатын түмэлигэр (Климентовтар үөскээбит-үүммүт, төрөөбүт төрүт сирдэрэ), Наахара орто оскуолатын (эбэбит Татьяна Михайловна төрөөбүт, үөрэммит дойдута, Терентий Дмитриевич Климентов учууталлаабыт, завучтаабыт оскуолата) түмэлигэр уонна улуус кыраайы үөрэтэр түмэлигэр муспут матырыйаалбынан альбом оҥортооммун туттаран, сэриигэ өлбүттэр кэриэстэрин үйэтитиигэ сэмэй кылааппын оҥорбутум. 2005 сылтан Табаҕа орто оскуолатыгар ини-бии Климентовтар ааттарынан стипендия олохтообутум, онно Николай Романович Климентов, ини-биилэр сиэннэрэ, кыттыһар. Мантан салгыы Климентовтар, онтон Григорьевтар аймахтар тустарынан тугу билбиппин кэнчээри ыччаппытыгар анаан суруйабын.</p>\n<p><strong>2. </strong><strong>б</strong><strong>аһа. Климентовтар төрүттэрэ</strong></p>\n<p><strong>2.1. Төрүттэрэ Филипп Климентов – “Суруксут Силип”</strong></p>\n<p>    Наһаа тахсан, сайдан-үүнэн испит дьон эбиттэр. Климентовтар диэн Уччус Тараҕай нэһилиэгэр олорон ааспыт дьон. Төрүттэрэ Филипп Климентов диэн эбит, бу туһунан 1959 сыллаахха от ыйыгар улахан эдьиийдэрэ Өрүүнэ (Ирина Дмитриевна Климетова) быраатыгар Дмитрий Дмитриевичка кэпсээбитин суруммута Д.Д.Климентов дьиэтээҕи архыыбыгар баар.”Бу Климентов Филиби дьон “Суруксут оҕонньор” диэн ааттыыллар эбит. Кини Сиэги-үөт, Кураанах алаас диэн сирдэринэн олохсуйан олорбута эбитэ үһү. Үөрэхтээх эбитэ буолуо, улуус суруксута буола сылдьыбыт. Кини баара эрэ икки уоллаах эбит. Киэнньэ Уйбаан уонна Холтуун Ньукулай диэн. Холтуун Ньукулай улаханнара үһү. Кинини улахан күүстээх киһи дииллэрэ. Кэргэннээх эрээри биирдэ да оҕоломмотох. Биһиги таайбытын кытта бииргэ төрөөбүт Лоппойор Ньукулааһы (Бурнашову) уонна Атара эмээхсини ылан иитэн киһи оҥортообут. Ньукулаас уонна биһиги аҕабыт Миитэрэй бииргэ төрөөбүт Бурнашовтар эбиттэр, ону ини-бии Киэнньэ Уйбаан уонна Холтуун Ньукулай Климентовтар иитэн улаатыннарбыттар. Киэнньэ – Уйбаан Климентов бастакы кэргэниттэн Молой Мэхээлэ уонна Хобороос төрөөбүттэр”.</p>\n<p>    Молой Мэхээлэттэн (Михаил Иванович) бастакы оҕото Павел Михайлович (Байбаас) төрүүр, киниттэн Гаврил Павлович Климентов 1923 с. төрөөбүт, 1942 сыллаахха атырдьах ыйыгар сэриигэ ыҥырыллан барбыт, 1943 сыллаахха кулун тутар ыйга сураҕа суох сүппүт. Быраа</p>\n<p><strong>       </strong><strong>2.2. Иитиллибитинэн Климентовтар</strong></p>\n<p><strong>    </strong>Холтуун Ньукулай ииппит Лоппойор Ньукулааһыттан, Николай Николаевич Климетовтан, Костя диэн оҕо 6-7 сааһыгар өлбүт, кэргэнэ Өкүлүүн маҥнайгы кэргэниттэн төрөөбүт кыыс Матрена Николаевна Климентова (Хаандыга) Ольга диэн кыыстаах, Валерий диэн уола өлбүт. Оттон Киэнньэ Уйбаан – биһиги эһэбит. Кинини “Балык Уйбаан” диэн эмиэ ааттыыллара эбитэ үһү. Иккитэ кэргэннэммит. Бастакы кэргэниттэн, этэн аһарбыппыт курдук, Молой Мэхээлэ кэлин Байбаас, Токкороо Бүөтүр, Тэҥкэ, Балбаара (Уллуҥнуур кэргэнэ) диэн оҕолордооҕо. “Киэнньэ Уйбаан иккис кэргэнэ Екатерина Васильевна Шамаева (Маттаахаан) диэн. Кини аҕата Буостай Баһылай Хара нэһилиэгин баайа эбит. Маттаахаан Кэтэриинэ дь: сааһыгар сүктүбүт. Сүрдээх сытыы-хотуу, тыллаах-өстөөх дьахтар эбитэ үһү. Эрин Киэнньэ оҕонньору утары көрдөрбөтөҕө үһү. Сир былдьаһан чугастааҕы ыалларын – Сымыыт Өндөрөйү, Чаччаҕай уола Дор Оҕонньору кытта охсуһара үһү. Уҥуоҕунан кыра эрээри сүрдээх суон, улахан сирэйдээх, модьу эмээхсин эбитэ үһү. Төбөтө салҕа эбит. Ол иһин кэлин оҕолор эбэлэрин дьээбэлиир эбиттэр. Тэрэнтэй: “Лэҥкээһэй, Лэҥкээһэй...”- дии-дии төбөтүн эргичиҥнэтэ-эргичиҥнэтэ куотан хаалара үһү. Эмээхсин маһынан быраҕан хаалара үһү. Сүтэн кэлээт сотору соҕус Суруксут оҕонньоргокыайан айааһамматах ат баарын айааһаабыта үһү. Ол курдук наһаа үлэһит дьахтар эбит. Биирдэ эрэ төрөөбүт. Иккитигэрбарбыт кыыс оҕото тумнастан өлбүтүн кэннэ биирдэ да оҕоломмотох. Дьэ ол иһин Тараҕайга Махсыын Бурнашов диэн сэттэ уоллаах оҕонньортон мин аҕабын, төрөөбүтэ 15 хоммут оҕону, иитэ ылаллар. Лоппойору Холтуун Ньукулай, Миитэрэйи Киэнньэ Уйбаан Климентовтар ииппиттэр.</p>\n<p>    Дьэ биһиги эһэбит “Киэнньэ Уйбаан, Маттаахаан Кэтириис буолан Ньаараҕа сир-уот тэринэн, оҕо ииттэн ыал буолан олорбуттар. Маҥнай отор дьиэ кэнинээҕи ампаар дьиэҕэ, онтон отор дьиэни туттан олорбуттар. Кэнники аҕам улаатан, туран, ыал буолан иһэн арҕаа балаҕаны туттан, онтон 1924 сыллаахха куулаҕа саҥа нуучча дьиэтин туттан олорбуттар. Ньаараҕа биһиги эһэбит ааҕы кытта Сымыыт Өндөрөй (Гавриил Андреевич Левин аҕата), Хаһытыкылар – Архыып, Чалыр Сэмэн, Батаҥа Өлөксөй, Түөтэйэ Бүөтүр, Ньолоорбо Бүөтүр Ыстаараһыннар аҕалара олорбуттар эбит. Маттаахаан Сымыыт Өндөрөйү, Хаһытыкы Бөтүрүүскэни кытта куруук этиһэрэ, үөхсэрэ, охсуһара үһү”.</p>\n<p><strong>2.4. </strong><strong>Кэскил дьиэ-кэргэҥҥэ түстэнэр</strong></p>\n<p>     Аҕа дойду улуу сэриитэ хас биирдии ыал дьылҕатыгар суолун-ииһин хаалларбыта. Мин ийэбинэн хос эһэм Климентов Егор Дмитриевич убайдара Николай, Прокопий, Терентий, Константин Аҕа дойду көмүскэлигэр олохторун толук уурбуттарын, Кыайыы туох сыананан ситиһиллибитин, хаалбыттар тыылга Кыайыыны уһансан күүһү таһынан үлэлээбиттэрин, хайдах-туох дьон этилэрин дьоммуттан истэн билэбин. 1941 с. саҕаламмыт Аҕа дойдуну көмүскүүр сэрии 20-тэн тахса мөлүйүөн сэбиэскэй киһи тыынын быспыта дииллэр. Аҕа дойду улуу сэриитигэр Саха сириттэн биир ыалтан түөрт бииргэ төрөөбүттэр фроҥҥа баран өлбүттэрэ олох аҕыйах. Биир итинник ыалынан Мэҥэ-Хаҥалас улууһун Тараҕай нэһилиэгиттэн Климентовтар буолаллар.</p>\n<p>    Уон биир оҕолоох Дмитрий Иванович, Анна Васильевна Климентовтар оҕолорун хайдах иитэн-үөрэтэн, такайан улаатыннарбыттара, биһиэхэ, ыччаттарыгар үтүө холобур буолар.</p>\n<p>    Дмитрий Иванович Сэбиэскэй былаас буолуутугар саҥа олоххо тардыһыыта күүһүрбүтэ. Бүтэйдээххэ аан бастаан тэриллибит кредитнэй табаарыстыбаҕа ким хайа иннинэ чилиэнинэн киирбитэ. Бэйэтэ киирбитин таһынан, чугастааҕы ыалларын тардыбыта. Нэһилиэккэ бстаан артыаллар тэриллиилэригэр көх-нэм буолан, “Уччук” диэн холбоһук табаарыстыбаны тэрийсибитэ. Ол табаарыстыбаҕа Г.П.Абрамов, Д.П.Керемясов, Д.И.Бурнашев-Тоҥ Суорун, Д.Н.Бурнашев киирбиттэрэ.</p>\n<p>    Климентовтар, дьон-сэргэ ахтарынан, үөрэх айдааннаах ыал эбиттэр. Аҕалара Дмитрий Иванович нэһилиэнньэни бүттүүн кэлимсэ үөрэхтээһин саҕаламмытыгар обургу оҕолорун үөрэттэрбитэ. Онтон оскуола арыллыбытыгар хас да кыра оҕолорун өйүөнэн үөрэттэрэр кыахтара тиийбэтэҕэ. Оҕолорун үөрэхтээх дьон оҥортуур баҕа санаата туолар кыаҕыттан суоҕуттан аҕалара улаханнык мунчааран: “Маннык үтүө кэм, сэбиэт былааһа кэлбитигэр оҕолорум биһиги курдук үөрэҕэ суох хааларгыт табыллыбат” – диир этэ.</p>\n<p>    “Биһиги баайбыт-дуолбут – оҕолорбут. Атын баайа суох ыалбыт. Бу кыра дьоннорбутун дойдуларыгар-сирдэригэр, дьонноругар-сэргэлэригэр туһалыыр гына улаатыннарар баҕалаахпыт”, - диирэ үһү аҕалара. </p>\n<p>    Бу үтүө санаатын толороору, холкуоһуттан көҥүллэтэн, 1929 с. Дьокуускайга көһөн киирбиттэр. Уола Дмитрий Дмитриевич Климентов ахтарынан, Петровскай уулуссатыгар турар 18 № - дээх олбуорга биир дойдулааҕа Старостин Байбал (Күөх Байбал) диэн киһилиин балаҕан атыыласпыт. Аҕалара бэртээхэй мас ууһа буолан, онно салҕааһын туттан, кэҥэттэн олорбуттар. Чэй үүтүгэр диэн ийэлэрэ биир тарбыйахтаах ынаҕы, аҕалара көлүнэр биэтин илдьэ киирбиттэр. Дьокуускайга аҕалара тутууга уона “Туус-Балык” тэрилтэҕэ үлэлээбит. Прокопий, Терентий, Анастасия, Константин уонна мин хос эһэм Дьөгүөр бары ол балаҕантан отой чугас, билиҥҥинэн Дьокуускай 2 №-дээх оскуолатыгар үөрэнэн барбыттар. Оҕолорун ити курдук үөрэттэрэ сылдьан аҕалара 1934 с. суох буолбут.</p>\n<p>    Аҕалара баҕа санаата туолан Прокопий үп техникумун бастакы кууруһун, Терентий учуутал техникумун, Анастасия эмп техникумун, Константин сибээс техникумун бүтэрбиттэр, кыралара эмиэ хастыы да кылаас үөрэхтэммиттэр.</p>\n<p>    Ити курдук сэрии иннинэ бу ыалтан бастакы үөрэхтээх, анал идэлээх дьон тахсан испиттэр эбит. Сэрии буолбатаҕа буоллар балар үүнэн-сайдан, киһи киэн туттар дьоно буолуохтара хааллаҕа. Таайдарбыт Николай, Прокопий, Терентий, Константин Аҕа дойду көмүскэлигэр баара-суоҕа 20, 30, 40 саастарыгар олохторун толук уурбуттара. Түөрт ини-бии кырыктаах сэрии толоонуттан эргиллибэтэхтэрэ.</p>\n<p>    Константин Дмитриевич Климентов 1916 с.т. этэ. 1933 с. Майа сэттэ кылаастаах оскуолатын бүтэрбитэ. 1933-1936 сс. Дьокуускайга сибээс техникумугар үөрэммитэ, Мэҥэ-Хаҥалас оройуонугар сибээс үлэһитинэн сылдьыбыта. 1937-1938 үөрэх дьылыгар Дьокуускайдааҕы байыаннай оскуола курсана. 1938-1939 сс. 1-кы нүөмэрдээх колонияҕа ВОХР байыаһынан үлэлээбитэ. 1939-1941 сс. Свердловскайга ВТУЗ городокка байыаннай-пехотнай училище курсанынан сылдьыбыта. 1941 с. ыам ыйыгар үөрэҕин бүтэрэн, лейтенант званиелаах Псковскай уобаласка Идрица диэн пограничнай бөһүөлэккэ ананан тиийбитэ. Сэрии бастакы күнүттэн кыргыһыыга кыттыбыта. Ол туһунан дьонноро 1941 с. сэрии бастакы күннэригэр суруйбут суругун туппуттар. “Баҕар эргиллиэм, таҥаспын ыыттым, уураарыҥ”, - диэн суруйбут эбит. Баһыылката кэлбэтэх. Киниттэн уонна туох да сурах, сурук-бичик туппатахтар. Бу курдук Константин сэрии саҕаламмыт бастакы күннэригэр өлбүт. Кэлин биллибитинэн, кини Идрица куоракка көмүллүбүт. Баара эрэ ньө саастааҕа, кэргэн да ыла илигэ, оҕо да суоҕа. Бииргэ төрөөбүт быраата Климентов Дмитрий Дмитриевич ахтыбытынан, кини сүрдээх сымаҕас, эйэҕэс майгылааҕа. Уруһуйдьут эбит. Кыра бырааттарыгар көрбүт киинэлэрин, аахпыт кинигэлэрин туһунан элбэхтик сэһэргиир, тупсаҕайдык кэпсиир эбит. Бэс ыйыгар, окко киириэх иннинэ, нэһилиэктэринэн ыһыахтар буоллахтарына хос эһэм Егор Дмитриевич убайдарынаан илии-атах оонньуутугар, тустууга кыттар эбиттэр. Бырааттыылар эт-хаан өттүнэн сайдыылаах, бэйэлэрин кыанар, дьону кытта тэҥҥэ үлэлиир, ханнык да үлэттэн толлон турбат дьон эбиттэрэ үһү. Биирдэ хос эһэм 2-с Наахара ыһыаҕар убайынаан Константинныын иккиэн тустууга бастаан кэлбиттэр. Сорох ыһыахтарга ат сүүрдэллэрэ үһү.</p>\n<p>    1942 с., бэс ыйын 27 күнүгэр иккис улахан хомуурга икки ини-бии, Николай уонна Терентий, тэҥинэн ыҥырыллыбыттар. Климентов Николай Дмитриевич уолаттартан саамай улаханнара. Кини 1902 с. төрөөбүт. Осуолаҕа үөрэммэтэх. 1931-1933 сс. саҕана ликбеһи барбыт. Онон бэрт муҥунан наадатын бэлиэтэнэр уонна илии баттыыр эрэ эбит. Александра Романовна диэн кэргэннээҕэ, 1926 с. төрөөбүт Арамаан диэн уоллаахтара. Николай төрөөбүт нэһилиэгиттэн аармыйаҕа ыҥырыллыар дылы тэйбэтэх. 1931 с. “Сүбэ” диэн кыракый холкуос тэриллибитигэр чилиэнинэн киирбит. Баара эрэ 30-40 хаһаайыстыбалаах кыараҕас артыал “Алаас” уонна “Үрэх” диэн икки производственнай биригээдэлээҕиттэн “Алаас” диэн биригээдэтигэр наар биригэдьииринэн, онтон 1935-1938 сс. холкуос бэрэссэдээтэлиэн үлэлээбит. Мин хос эһэбинээн, быраатынан Дьөгүөрдүүн, хаста да холкуос түһээнин толорон, уонна сырыыны-айаны кыайар буоланнар, Ньылхаҥҥа, Алдан бириискэлэригэр ындыы таһыытыгар баран кэлбиттэр. Оччолорго хас биирдии холкуостан үстүү-түөртүү сыарҕа аттаах икки-үс киһини сыл аайы хайаан да ыыталлар эбит. Бу курдук холкуоһа чэчирии сайдарын туһугар бары күүһүн-уоҕун биэрбитэ. Аармыйаҕа 1942 с. бэс ыйыгар ыҥырыллыбыт. Фроҥҥа барарыгар холкуоһун дьонугар: “Сэриигэ барбытдьону суохтаппакка, үчүгэйдик үлэлээҥ, холкуоскутун сайыннара, барҕарда туруҥ. Өлөксөөс, эн (кэргэнигэр) эр дьону суохтаппат төһүү үлэһит буолаар. Биһиги, баҕар, эргиллиэхпит суоҕа”, - диэбитэ үһү. Үөрэҕэ суох буолан аармыйаттан суруйбатах эбит. Дьонугар кини хайдах, ханна сылдьыбытын туоһулуур ханнык эмит сурук-бичик оҕото суох. Кинини 1943 с. олунньу ыйыгар сураҕа суох сүппүт диэн военкоматтар эппиттэр. </p>\n<p>    Прокопий Дмитриевич Климентов 1910 с. төрөөбүтэ. Дьокуускайдааҕы финансовай техникум бастакы кууруһун бүтэрбитэ. Тыҥатыгар очагтаах буолан салгыы кыайан үөрэммэтэҕэ(ийэлэрэ 1934 с. сөтөл буолан өлбүтэ, онон оҕолор үксүлэрэ сөтөллөөх-туберкулезтаах этилэр). 1935-1939 сс. дойдутугар тахсан, “Сүбэ” холкуоска счетоводунан үлэлээбит. 1940-1941 сс. Прокопий Дьокуускайга киирэн холкуостар счетоводтарын куурустарыгар үөрэммит. Ол үөрэнэ сырыттаҕына 1941 с. атырдьах ыйыгар аармыйаҕа ылбыттар. Кини сэрииттэн эмиэ төннүбэтэҕэ. 1944 с. кулун тутар ыйга сураҕа суох сүппүтэ эрэ биллэр.</p>\n<p>    Климентов Терентий Дмитриевич 1912 с. төрөөбүт. 1936 с. учуутал техникумун бүтэрбит уонна 1942 с. сайыныгар дылы Наахара 7 кылаастаах оскуолатыгар математика уонна физика учууталынан, кэнники үс сыл үөрэх чааһын сэбиэдиссэйинэн үлэлээбит. Кэргэннэнэн, икки бастакы уолаттара иккилэригэр сылдьан, тымныйан өлүтэлээн хаалбыттар. 1942 с. бэс ыйын 27 күнүгэр аармыйаҕа ыҥырыллар. Кэргэнэ үс ыйдаах ыарахан хаалар. Бу оҕо 1942 с. ахсынньы 26 күнүгэр төрөөбүт, онон Терентий Дмитриевич уол оҕоломмутун истэн баран, уола 6 ыйдааҕар өлбүт. Терентий 1943 с. от ыйыгар Орел куораттан чугас Марьино дэриэбинэ таһыгар госпитальга өлбүт. Кини аатырбыт Орел-Курскай дуҕатын кыргыһыыларыгар кыттыбыт, 9-с гвардейскай стрелковай дивизия 4-с гвардейскай стрелковай полкатыгар сулууспалаабыт. Орловскай уобалас Должанскай оройуонун Марьино дэриэбинэтигэр көмүллүбүт. Өлбүтүн туһунан биллэриитэ 1943 с. сайын атырдьах ыйыгар кэлбит.</p>\n<p><strong>Түмүгэ</strong></p>\n<p>    Быйыл ыам ыйын 9 күнүгэр Кыайыы буолбута 80-сыллаах үбүлүөйүн бэлиэтээбиппит. Ол ынырык сэрии бүппүтүн кэнниттэн 80 сыл ааста. </p>\n<p>    Бу күн албан ааттаах хамандыырдарга уонна байыастарга, дойду маршалларыгар уонна борустуой саллааттарга сүгүрүйэбит.</p>\n<p>   Ити курдук алдьархайдаах аан дойду улуу сэриитигэр түөрт ини-бии Климентовтар Аҕа дойдуларын туһугар, кэнчээри ыччаттарын туһугар Россия киэҥ-нэлэмэн ньууругар охтубуттара, көмүс уҥуохтара онно хаалбыта.</p>\n<p>    Климентовтар оҕолоро кэлин: “Биһиги бука бары аҕалаах ийэбититтэн үлэҕэ дьулуурдаах, харыстаммат буолууга, дьоҥҥо-сэргэҕэ истиҥ, амарах, үтүө сыһыаннаах, ыарахаттары-күчүмэҕэйдэри кытта охсуһууга тулуурдаах буолууга үөрэммит эбиппит”, - диэн ахталлара.</p>\n<p>    2015 с. саҥаспыт Климентова Анна Иннокентьевна таһаартарбыт “Өйдүүбүт... Махтанабыт... Сүгүрүйэбит...” кинигэтэ биһиги төрүччүбүтүн өссө дириҥник хасыһан үөрэтэрбитигэр олук уурда. Аҕа көлүөнэбит дьоһун олоҕун өйдүү-саныы сылдьар, сэрии толоонноругар охтубут хаан уруу дьоммут сырдык ааттарын үйэтитэр, дьоҥҥо-сэргэҕэ тиэрдэр – ытык иэспит буолар.</p>\n<p>    Кыайыы күнэ биһиги дьиэ кэргэҥҥэ, бүтүн аймахха олус улахан суолталаах, чахчы даҕаны “харах уулаах бырааһынньык” буолар. </p>\n<p>    Биһиги, Климентовтар ыччаттара, төрүт дьон төрүөхтэрэ буоларбытынан киэн туттан тураммыт, кинилэр ааттарын үрдүктүк тутан, түһэн биэрбэт гына үөрэнэргэ, үлэлииргэ-хамсыырга, олорорго кыһаллыахпыт.</p>\n<p><strong>Туһаныллыбыт литература</strong></p>\n<ul>\n<li>Д.Д.Климентов дьиэтээҕи архыыба. 2014 с.</li>\n<li>Т.М.Климентова ахтыыта. 2000-2004 сс.</li>\n<li>Илья Петров – Мастаах Уола “Ийэлэр харахтарын уута”, Дьокуускай, 1996 с.</li>\n<li>Өйдөбүнньүк кинигэ. Майа. 1995 с. Н.И.Ефремов</li>\n<li>Махтанабын, сүгүрүйэбин. Е.Сивцева. «Эркээйи», 2013 с. алтынньы 25 күнэ.</li>\n<li>Сырдык сулус буолан сыдьаайан. Майа с. 2006 с. “Эркээйи” редакциятын таһаарыыта. </li>\n</ul>','2026/03/pub_20260302_103116_3b792fbf.docx','Климентовтар дакылаат.docx',35502,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',3,'serii-haaryybatah-dono-dien-suoh',NULL,NULL,26,0,'published',NULL,'auto_approved','2026-03-02 10:31:17',0.90,'ready','2026-03-02 10:31:17','2026-03-02 07:31:16','2026-03-04 22:30:29'),(24,1981,'Применение технологии проблемного обучения на уроках математики в 5 классе','Публикация описывает технологию проблемного обучения как метод развития познавательной активности учащихся на уроках математики в 5 классе. Рассматриваются этапы постановки проблемы, выдвижения гипотез, проверки гипотез и рефлексии. Приводятся примеры заданий для реализации проблемного метода.','<p><strong> «Применение технологии проблемного обучения на уроках математики в 5 классе»</strong></p>\n<p><strong>Введение</strong></p>\n<p>Проблемное обучение — это педагогическая технология, направленная на развитие познавательной активности учащихся путем постановки перед ними учебных задач, решение которых требует самостоятельного поиска и анализа информации.</p>\n<p> Применение этой методики особенно актуально в старшей школе, включая уроки математики в 5 классе, поскольку именно здесь закладываются основы понимания предметных закономерностей, формируется интерес к обучению. </p>\n<p><strong>Цель: </strong>представить основные принципы и методы проблемного обучения математике в 5 классе, показать, каким образом данная методика способствует развитию мыслительных способностей учеников и повышению уровня усвоения учебного материала.</p>\n<p><strong>Что такое проблемное обучение?</strong></p>\n<p>Проблемное обучение - это методический подход, основанный на постановке учителем специальной учебной проблемы и создании условий для самостоятельной исследовательской деятельности ученика. </p>\n<p>Проблемная ситуация стимулирует мотивацию ребенка, формирует способность рассуждать, аргументировать свою позицию и решать нестандартные задачи.</p>\n<p><strong>Практически технологию проблемного обучения можно внедрить </strong><strong>в несколько этапов.</strong></p>\n<p><strong>Этап 1. Постановка проблемы</strong></p>\n<p>Например, учитель математики ставит перед учениками следующую задачу:</p>\n<p>«Маша нарисовала прямоугольник, длина которого равна ширине плюс три сантиметра. Площадь прямоугольника составляет 28 квадратных сантиметров. Найдите длину и ширину прямоугольника».</p>\n<p>Эта задача вызывает затруднения у большинства учеников, так как требует перехода от простых арифметических операций к алгебраическому мышлению.</p>\n<p><strong>Этап 2. Выдвижение гипотез</strong></p>\n<p>Далее ученики начинают предлагать разные способы решения:</p>\n<ul>\n<li>Один ученик высказывается, что попробует составить уравнение, основываясь на известных формулах площади прямоугольника (S=<em> </em><em>ab</em>, где <em>b</em>— ширина, а длина равна <em>a</em><em>=</em><em>b</em><em>+3</em>).</li>\n<li>Другой ученик пытается угадать значения ширины и длины методом проб и ошибок.</li>\n</ul>\n<p>Эти гипотезы становятся отправной точкой для дальнейшего исследования.</p>\n<p><strong>Этап 3. Проверка гипотез</strong></p>\n<p>Дети совместно решают составленное уравнение и проверяют полученный результат. В ходе проверки обнаруживается, что первый способ (алгебраический) оказался наиболее эффективным и быстрым.</p>\n<p><strong>Этап 4. Рефлексия и обобщение полученных выводов</strong></p>\n<p>Завершающим этапом является обсуждение найденного решения и выделение основных моментов:</p>\n<ul>\n<li>Возможность составлять уравнения для описания реальных жизненных ситуаций.</li>\n<li>Важность выбора оптимального метода решения.</li>\n<li>Полезность проверки правильности решения обратным подсчетом.</li>\n</ul>\n<p><strong>Примеры заданий для уроков математики в 5 классе</strong></p>\n<p>Рассмотрим конкретные задания, направленные на реализацию проблемного метода на уроках математики:</p>\n<p><strong>Пример №1. Задача </strong><strong>на нахождение</strong><strong> площади прямоугольника</strong></p>\n<p>Учащимся предлагается рассмотреть квадрат со стороной 6 см и вычислить его площадь (S=a2)(<em>S</em>=а·а). Затем ставится новая проблема: «Что произойдёт с площадью квадрата, если одну сторону увеличить вдвое?» Учащиеся самостоятельно исследуют ситуацию, строят новые фигуры и сравнивают полученные результаты, формируя вывод о зависимости площади от изменения сторон.</p>\n<p><strong>Пример №2. Решение уравнений методом подбора</strong></p>\n<p>Задание типа: «Решите уравнение x+7=12» Дети сначала пытаются решить уравнение интуитивно («подбором»), после чего вместе находят алгоритм действий, приводящий к правильному решению. Таким образом, учащиеся постепенно переходят от эмпирического способа познания к научному способу.</p>\n<p><strong>Пример №3. Исследование симметрии фигур</strong></p>\n<p>Учитель показывает различные геометрические фигуры и предлагает детям выяснить, какая фигура обладает осью симметрии, и почему. После обсуждения дети формируют понятие, что такое  ось симметрии, её свойства, выявляя взаимосвязи между различными видами симметричных объектов.</p>\n<p><strong>Преимущества проблемного обучения</strong></p>\n<p>Использование проблемного метода позволяет достичь следующих положительных эффектов:</p>\n<ul>\n<li>Повышение мотивации к учебе.</li>\n<li>Развитие аналитического мышления и способности решать практические задачи.</li>\n<li>Формирование умения сотрудничать и взаимодействовать друг с другом.</li>\n<li>Глубинное осознание изучаемых понятий и законов математики.</li>\n</ul>\n<p>Однако важно учитывать некоторые сложности внедрения данной методики:</p>\n<ul>\n<li>Требуется больше времени на подготовку уроков и организацию взаимодействия детей.</li>\n<li>Необходимо обеспечить высокий уровень вовлеченности всех участников образовательного процесса.</li>\n</ul>\n<p><strong>Заключение</strong></p>\n<p>Таким образом, использование технологии проблемного обучения на уроках математики в 5 классе является эффективным способом повышения качества образования. Оно помогает развивать мышление школьников, формировать умение применять знания на практике и повышать общий уровень успеваемости.</p>','2026/03/pub_20260302_184049_f8ef2242.docx','технология проблемного обучения.docx',39002,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',1,'primenenie-tehnologii-problemnogo-obucheniya-na-urokah-matematiki-v-5-klasse',NULL,NULL,21,0,'published',NULL,'auto_approved','2026-03-02 18:40:50',0.95,'pending','2026-03-02 18:40:50','2026-03-02 15:40:49','2026-03-04 22:13:30'),(25,1984,'Конспект урока по литературному чтению \'С. Есенин. Черёмуха\'','Методическая разработка представляет собой конспект урока по литературному чтению для 3 класса на тему \'С. Есенин. Черёмуха\'. Урок включает в себя организационный момент, речевую разминку, беседу о поэте, работу над стихотворением и итог с рефлексией. На уроке используются мультимедийные материалы, проводится анализ стихотворения и его выразительное чтение.','<p><strong>Методическая разработка</strong></p>\n<p><strong>Конспект урока по литературному чтению</strong></p>\n<p><strong>В 3 «з» классе</strong></p>\n<p><strong>на тему «</strong><strong>С.Есенин</strong><strong>.Ч</strong><strong>ерёмуха</strong><strong>»</strong></p>\n<p>Тип урока: открытие новых знаний.</p>\n<table>\n<tr>\n<th>Этапы урока</th>\n<th>Деятельность учителя</th>\n<th>Деятельность учащихся</th>\n<th>УУД</th>\n</tr>\n<tr>\n<td>1.Организационный момент<br>1 минута</td>\n<td>Проверка готовности к уроку.<br>-На протяжении урока будьте внимательны, чтобы вы смогли усвоить материал и легко ответить на вопросы.</td>\n<td>Приветствуют, садятся на свои места, настраиваются на работу.</td>\n<td> <br> <br> <br> <br>Метапредметн:<br>Регулятивные</td>\n</tr>\n<tr>\n<td>2.Речевая разминка<br>5 минут</td>\n<td>На слайде пословица: «Никакое искусство не достигнет природы. » .<br>-Прочитайте про себя пословицу, указанную на слайде. <br>-Что она означает? Как вы её понимаете?<br> <br> <br> <br>-Читаем её хором в медленном  темпе.<br>А теперь немножко быстрее.<br>Всем нужно читать в одно время. ( Читаю вместе с ними)<br> -Молодцы! А теперь, кто хочет прочитать выразительно?<br>-А кто может прочитать эмоционально, с восклицанием?/<br>Вопросительно?<br> <br> <br> </td>\n<td> <br> <br> <br>Читают пословицу.<br> <br> <br>Она означает, что никакое творение человека никогда не превзойдёт то, что сотворено природой.<br> <br>Читают медленно, затем быстрее.<br> <br> <br>Читает желающий, если нет желающих, выбираю сама.</td>\n<td> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br>Метапредметн:<br>Регулятивные</td>\n</tr>\n<tr>\n<td>3.Беседа о поэте<br>15 минут</td>\n<td>-Хорошо! Послушайте внимательно, и скажите, узнаёте ли вы эти строки?<br>Белая берёза<br>Под моим окном<br>Принакрылась снегом<br>Словно серебром<br>-Кто автор этого стихотворения?<br>-Верно. С творчеством Сергея Александровича не знаком,<br>наверное, лишь тот, кто ещё не ходит в школу. А узнаете ли вы его по фотографии? (На слайде три портрета поэтов) На каком портрете изображение Есенина? <br> <br>Включаю отдельно портрет Есенина с годами жизни.<br>-Что вы можете сказать о его чертах лица?<br>-А как вы думаете, какие стихотворения может писать человек с такой внешностью?<br>-А сейчас послушайте краткую биографию поэта, и вы узнаете, так это или нет.<br>Сергей Александрович Есенин родился под Рязанью в селе Константиново. <br>В раннем детстве полюбил Сергей русскую природу – он чувствовал себя частью этой природы. А писать он начал рано – в девять лет. Пусть и прожил он всего тридцать лет, но он успел написать очень много стихотворений и поэм. Его отличают необыкновенная искренность, удивительная чуткость к земным краскам, простота и прозрачность стиха.<br>-Вот видите, вы угадали. Его стихотворения так же нежны как и черты лица. <br>Давайте немного отдохнём. Встаньте, пожалуйста, возле своих парт так, чтобы было удобно всем. Игра «Мы охотимся на льва»</td>\n<td> <br> <br> <br> <br> <br> <br> <br>-Сергей Александрович Есенин.<br> <br> <br> <br> <br> <br> <br>Выбирают среди Есенина, Маяковского, и Толстого.<br> <br> <br>-Он красивый, на вид добрый.<br> <br>-Красивые, о природе и любви.<br> </td>\n<td> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br>Личностные</td>\n</tr>\n<tr>\n<td>4.Работа над стихотворением<br>20 минут</td>\n<td>-Сегодня мы с вами познакомимся со стихотворением «Черёмуха». Откройте учебник на 55 странице. Послушайте прочтение этого стихотворения и одновременно прослеживайте по тексту. <br>Включаю запись.<br>-Понравилось вам произведение?<br>-Каким оно вам показалось?<br>-О чём это произведение?<br> <br>-Что означает слово душистая?<br>-Правильно, и пряная означает то же самое. Это слова синонимы. <br>-А что значит вкрадчивый? Как думаете?<br> <br> <br> <br>-Медвяная роса, это какая? На что она похожа?  <br> <br> <br>А что такое проталина?<br>-Есть гремучая змея, а что значит гремучая волна?<br>-Круча это спуск. А по названию, как думаете, какой это спуск?<br>-Есть ещё в  стихотворении слова, которые вы не знаете?<br>-Какие слова выбирает поэт, чтобы мы услышала, как поёт ручей?<br> <br> <br> <br> <br>-Какая картина возникает в вашем воображении, когда вы читаете строчки «И ветки золотистые, что кудри, завила»?<br>-Как думаете, почему поэт изображает черёмуху и ручей как живых?<br>-Как нужно прочитать это стихотворение, чтобы звучало выразительно, и передавало всю суть и отношение поэта к природе?<br>-Кто может прочитать стихотворение выразительно?<br> <br>-Сегодня и мы с вами будем творить, только не стихи писать, а рисовать иллюстрацию к произведению, которое мы сегодня изучаем. На рисунок примерно 5-10 минут.<br>Раздаю листы.<br>Затем дети по очереди выходят к доске и описывают свой рисунок.<br> </td>\n<td> <br> <br> <br> <br> <br> <br> <br> <br>Слушают запись и читают в учебнике.<br> <br> <br> <br> <br>-О черёмухе, весне, красивой природе.<br> <br>-Ароматная, с острым запахом.<br> <br> <br>-Это старающийся вызвать доверие, расположение к себе. Который вкрадывается.<br> <br>– Липкая, сладкая жидкость, похожая на мёд, отсюда и название.<br> <br>-Место, где стаял снег.<br>-Громкая, шумная.<br> <br>-Крутой.<br> <br>Проверяют, все ли слова им знакомы.<br> <br>-А рядом, у проталинки, в траве между корней, бежит, струится маленький серебряный ручей.<br> <br>-Густая крона дерева, листья блестят.<br> <br> <br>-Он очень любил природу, чувствовал себя частью природы.<br> <br>-Нужно прочитать нежно, с любовью к природе.<br> <br> <br>Слушаю несколько выразительных прочтений.<br> <br> <br> <br> <br> <br> <br> <br>Рисуют иллюстрацию.</td>\n<td> <br> <br> <br> <br> <br> <br> <br> <br>Метапредм.:<br>Коммуникат.<br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br>Метапредм.:<br>Познават.<br> <br> <br> <br> <br> <br> <br> <br> <br>Метапредм.:<br>Познават.<br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br> <br>Метапредм.:<br>Коммуникат.</td>\n</tr>\n<tr>\n<td>5.Итог. Рефлексия.</td>\n<td>-Подведём итоги нашего урока.<br>-С каким произведением мы познакомились сегодня?<br>-Понравилось оно вам?<br>-Кто автор этого стихотворения?<br>-Что вы запомнили из биографии поэта?<br>-Когда поэт написал своё первое стихотворение?<br>-Почему у Есенина так чутко и точно получается передавать облик природы?<br>-Какие строки из «Черёмухи» понравились вам больше всего?<br> <br>-Понравился вам наш урок?<br>-Чему вы сегодня научились? Что нового узнали?<br>-Какие трудности у вас возникали?</td>\n<td> <br> <br>-«Черёмуха».<br> <br> <br>-Да.<br>-Есенин Сергей <br>Александрович<br>Говорят, что запомнилось.<br> <br>-В 9 лет.<br> <br>-Очень любит природу, считает себя её частью.<br> <br>Рассказывают, что им понравилось больше всего.</td>\n<td> </td>\n</tr>\n<tr>\n<td>6.Доманее задание</td>\n<td>Запишите домашнее задание: выучить стихотворение «Черёмуха». На следующий урок вам нужно его выразительно рассказать. А сейчас наш урок подошёл к концу. </td>\n<td>Записывают домашнее задание. </td>\n<td> </td>\n</tr>\n</table>\n<p> </p>','2026/03/pub_20260302_190424_e8843a65.docx','Михеева.Черёмуха.docx',21869,'application/vnd.openxmlformats-officedocument.wordprocessingml.document',1,'konspekt-uroka-po-literaturnomu-chteniyu-s-esenin-cheryomuha',NULL,NULL,21,0,'published',NULL,'auto_approved','2026-03-02 19:04:25',0.00,'ready','2026-03-02 19:04:25','2026-03-02 16:04:24','2026-03-05 02:52:15'),(26,1988,'Кроссворд-пособие \'Химия в нашей жизни\'','Кроссворд-пособие предназначено для закрепления знаний по теме \'Периодический закон и Периодическая система химических элементов Д.И. Менделеева\'. Включает вопросы и ответы по химическим элементам и их свойствам, подходит для учащихся 8 класса.','<p>Кроссворд-пособие «Химия в нашей жизни» </p>\n<p>к  теме «Периодический закон и Периодическая система химических элементов Д.И. Менделеева. 8 класс</p>\n<p><em><strong>Вариант 1. </strong></em></p>\n<table>\n<tr>\n<th>1</th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th>2</th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n<th></th>\n</tr>\n<tr>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td>4</td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td>12</td>\n<td></td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td>6</td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td>10</td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n<td></td>\n</tr>\n<tr>\n<td></td>\n<td></td>\n<td></td>\n<td>5</td>\n<td></td>\n<td></td>\n<td></td>\n<td></